using ByteForge.Toolkit.CommandLine;

// Command group with instance methods
[Command("file", "File operations command group")]
public class FileCommands
{
  // Instance method command within the group
    [Command("copy", "Copy a file from source to destination")]
    public void Copy(
        [Option("Source file path", "s")] string source,
        [Option("Destination file path", "d")] string destination,
        [Option("Overwrite existing files")] bool overwrite = false)
    {
        Console.WriteLine($"Copying {source} to {destination}");
        if (overwrite)
         Console.WriteLine("Overwrite mode enabled");

        File.Copy(source, destination, overwrite);
        Console.WriteLine("✓ Copy completed!");
    }

    [Command("move", "Move a file from source to destination")]
    public void Move(
      [Option("Source file path")] string source,
    [Option("Destination file path")] string destination)
    {
        Console.WriteLine($"Moving {source} to {destination}");
        File.Move(source, destination);
        Console.WriteLine("✓ Move completed!");
    }

    [Command("delete", "Delete a file", "del", "rm")]
    public void Delete(
        [Option("File path to delete")] string path,
     [Option("Force deletion without confirmation")] bool force = false)
    {
  if (!force)
        {
       Console.Write($"Are you sure you want to delete {path}? (y/n): ");
            if (Console.ReadLine()?.ToLower() != "y")
            {
    Console.WriteLine("Deletion cancelled");
           return;
    }
        }

        File.Delete(path);
        Console.WriteLine("✓ File deleted!");
    }
}

// Static method commands (top-level, not in a group)
public class UtilityCommands
{
    [Command("greet", "Greet a person with a custom message")]
    public static void Greet(
        [Option("Person's name to greet", "n")] string name,
        [Option("Custom greeting message")] string greeting = "Hello",
        [Option("Display greeting in uppercase")] bool uppercase = false)
    {
        string message = $"{greeting}, {name}!";

        if (uppercase)
            message = message.ToUpper();

        Console.WriteLine(message);
    }

    [Command("version", "Display application version", "ver", "v")]
    public static void ShowVersion()
    {
        var version = System.Reflection.Assembly.GetExecutingAssembly().GetName().Version;
        Console.WriteLine($"Application Version: {version}");
    }
}

