using ByteForge.Toolkit.CommandLine;
using System.Reflection;

// ═══════════════════════════════════════════════════════════════
// Complete Enterprise CLI Application Example
// ═══════════════════════════════════════════════════════════════

public class Program
{
    public static async Task<int> Main(string[] args)
    {
        var builder = new RootCommandBuilder("Enterprise Data Tool")
        {
  EnableHelp = true,
          EnableTypoCorrections = true,
            EnableCaseSensitivity = false,
       EnableParameterExplanation = true
        };

  // Custom banner
        builder.BannerAction = () =>
 {
            Console.ForegroundColor = ConsoleColor.Cyan;
  Console.WriteLine(@"
╔══════════════════════════════════════════╗
║   Enterprise Data Tool v2.0              ║
║   Advanced Command Line Interface        ║
╚══════════════════════════════════════════╝
");
  Console.ResetColor();
     };

        // Global options
  builder.AddGlobalOption(new GlobalOption(
         "verbose", 
         "Enable detailed logging",
      () => Environment.SetEnvironmentVariable("VERBOSE", "1"),
         expectsValue: false,
            "v"));

        builder.AddGlobalOption(new GlobalOption(
            "config",
       "Configuration file path",
         (path) => LoadConfig(path),
     expectsValue: true,
            "c"));

        // Load commands from assembly
    builder.AddAssembly(Assembly.GetExecutingAssembly());

        var parser = builder.Build();
        var result = parser.Parse(args);

        if (result.Errors.Any())
        {
            Console.ForegroundColor = ConsoleColor.Red;
            foreach (var error in result.Errors)
    Console.WriteLine($"Error: {error}");
     Console.ResetColor();
            return 1;
     }

        return await result.Invoke();
    }

 private static void LoadConfig(string path)
    {
        Console.WriteLine($"Loading configuration from: {path}");
    }
}

