[Command("database", "Database management commands", "db")]
public class DatabaseCommands
{
    [Command("backup", "Create database backup")]
    public async Task<int> Backup(
        [Option("Database connection string")] string connectionString,
   [Option("Backup file path")] string outputPath,
        [Option("Compression level (0-9)")] int compression = 5)
    {
   using (new ProgressSpinner($"Creating backup"))
        {
 Console.WriteLine($"Connection: {connectionString}");
 Console.WriteLine($"Output: {outputPath}");
            Console.WriteLine($"Compression: {compression}");

            await Task.Delay(3000); // Simulate backup
        }

        Console.WriteLine($"✓ Backup created: {outputPath}");
        return 0;
    }

    [Command("restore", "Restore database from backup")]
    public async Task<int> Restore(
        [Option("Database connection string")] string connectionString,
        [Option("Backup file path")] string backupPath,
        [Option("Overwrite existing database")] bool force = false)
    {
        if (!force)
        {
            Console.Write("This will overwrite the database. Continue? (y/n): ");
     if (Console.ReadLine()?.ToLower() != "y")
       {
    Console.WriteLine("Restore cancelled");
       return 0;
            }
     }

        using (new ProgressSpinner("Restoring database"))
     {
       await Task.Delay(4000); // Simulate restore
        }

        Console.WriteLine("✓ Database restored successfully!");
        return 0;
    }

    [Command("migrate", "Run database migrations")]
  public async Task<int> Migrate(
        [Option("Database connection string")] string connectionString,
        [Option("Target migration version")] string? targetVersion = null,
    [Option("Dry run without applying changes")] bool dryRun = false)
    {
      Console.WriteLine($"Migration mode: {(dryRun ? "Dry Run" : "Apply")}");

        using (new ProgressSpinner("Running migrations"))
        {
            await Task.Delay(2500);
   }

        Console.WriteLine("✓ Migrations completed!");
        return 0;
    }
}

