[Command("file", "File processing operations")]
public class FileCommands
{
    [Command("convert", "Convert file format")]
    public async Task<int> Convert(
        [Option("Input file path")] string input,
     [Option("Output file path")] string output,
        [Option("Target format")] FileFormat format,
   [Option("Encoding")] string encoding = "UTF-8")
    {
        Console.WriteLine($"Converting: {input} → {output}");
        Console.WriteLine($"Format: {format}");
        Console.WriteLine($"Encoding: {encoding}");

   using (new ProgressSpinner("Converting file"))
        {
       await Task.Delay(2000);
        }

  Console.WriteLine("✓ Conversion complete!");
        return 0;
    }

    [Command("validate", "Validate file integrity")]
    public void Validate(
        [Option("File path to validate")] string path,
        [Option("Validation type")] ValidationType type = ValidationType.Checksum)
    {
   Console.WriteLine($"Validating: {path}");
      Console.WriteLine($"Type: {type}");

        using (new ConsoleSpinner("Validating"))
      {
    Thread.Sleep(1500);
   }

  Console.WriteLine("✓ File is valid!");
  }

    [Command("compress", "Compress files")]
    public void Compress(
        [Option("Input file or directory")] string input,
    [Option("Output archive path")] string output,
        [Option("Compression algorithm")] CompressionType algorithm = CompressionType.GZip,
        [Option("Compression level (0-9)")] int level = 6)
    {
        Console.WriteLine($"Compressing: {input}");
        Console.WriteLine($"Output: {output}");
        Console.WriteLine($"Algorithm: {algorithm}, Level: {level}");

        using (new ConsoleSpinner($"Compressing with {algorithm}"))
        {
            Thread.Sleep(2000);
     }

     Console.WriteLine("✓ Compression complete!");
    }
}

