public class StandaloneCommands
{
    [Command("version", "Display version information", "ver", "v")]
    public static void ShowVersion()
    {
  var version = Assembly.GetExecutingAssembly().GetName().Version;
      var product = Assembly.GetExecutingAssembly()
          .GetCustomAttribute<AssemblyProductAttribute>()?.Product;
        var company = Assembly.GetExecutingAssembly()
            .GetCustomAttribute<AssemblyCompanyAttribute>()?.Company;

        Console.WriteLine($"{product} v{version}");
        Console.WriteLine($"© {DateTime.Now.Year} {company}");
    }

    [Command("info", "Display system information")]
  public static void ShowInfo()
    {
 Console.WriteLine("System Information:");
    Console.WriteLine($"  OS: {Environment.OSVersion}");
        Console.WriteLine($"  .NET: {Environment.Version}");
        Console.WriteLine($"  Processors: {Environment.ProcessorCount}");
        Console.WriteLine($"  64-bit: {Environment.Is64BitOperatingSystem}");
    }
}

