/*
Command-line usage examples:

# Global options
app.exe --help
app.exe --verbose database backup --connection-string "..." --output-path backup.bak
app.exe --config app.json file convert --input data.csv --output data.json --format Json

# Database commands
app.exe database backup --connection-string "Server=localhost" --output-path backup.sql
app.exe db restore --connection-string "..." --backup-path backup.sql --force
app.exe database migrate --connection-string "..." --target-version 1.5.0
app.exe db migrate --dry-run

# File commands
app.exe file convert --input data.csv --output data.json --format Json
app.exe file validate --path document.xml --type Schema
app.exe file compress --input /data --output archive.gz --algorithm GZip --level 9

# Standalone commands
app.exe version
app.exe info

# Aliases
app.exe db backup ...    (database → db)
app.exe ver        (version → ver)
*/

using ByteForge.Toolkit.CommandLine;

public class Program
{
    public static async Task<int> Main(string[] args)
    {
        // Create root command builder
        var builder = new RootCommandBuilder("My Command Line Application");

     // Add commands from assembly
        builder.AddAssembly(typeof(Program).Assembly);

        // Configure features
     builder.EnableHelp = true;
        builder.EnableTypoCorrections = true;
        builder.EnableCaseSensitivity = false;
    builder.EnableParameterExplanation = true;

        // Add banner
        builder.BannerAction = () =>
    {
            Console.WriteLine("╔══════════════════════════════════════╗");
    Console.WriteLine("║   My Application v1.0     ║");
  Console.WriteLine("╚══════════════════════════════════════╝");
          Console.WriteLine();
      };

        // Add global options
        builder.AddGlobalOption(new GlobalOption(
     "verbose",
          "Enable verbose output",
      () => Console.WriteLine("Verbose mode enabled"),
     expectsValue: false,
            "v"));

 builder.AddGlobalOption(new GlobalOption(
            "config",
      "Configuration file path",
            (value) => Console.WriteLine($"Using config: {value}"),
   expectsValue: true,
          "c"));

        // Build parser
        var parser = builder.Build();

        // Parse and invoke
        var result = parser.Parse(args);
        return await result.Invoke();
    }
}

// Example with custom error handling
public class CustomProgram
{
    public static int Main(string[] args)
    {
      try
   {
 var builder = new RootCommandBuilder("Enterprise App");
  builder.AddAssembly(typeof(CustomProgram).Assembly);

            var parser = builder.Build();
      var result = parser.Parse(args);

    // Check for parsing errors
            if (result.Errors.Any())
            {
      Console.ForegroundColor = ConsoleColor.Red;
                Console.WriteLine("Parsing errors:");
                foreach (var error in result.Errors)
           Console.WriteLine($"  • {error}");
         Console.ResetColor();
  return 1;
         }

          return result.Invoke();
        }
        catch (Exception ex)
      {
   Console.ForegroundColor = ConsoleColor.Red;
        Console.WriteLine($"Fatal error: {ex.Message}");
  Console.ResetColor();
            return -1;
     }
    }
}

