using ByteForge.Toolkit.CommandLine;

public class BackupCommands
{
    [Command("backup", "Backup files to destination")]
    public static void Backup(
        [Option("Source directory", "s")] string source,
        [Option("Destination directory", "d")] string destination)
    {
        using (var spinner = new ConsoleSpinner("Preparing backup"))
        {
            // Validation
            if (!Directory.Exists(source))
                throw new DirectoryNotFoundException($"Source not found: {source}");

            Directory.CreateDirectory(destination);
            Thread.Sleep(1000); // Simulate work
        }

        Console.WriteLine("✓ Preparation complete");

        using (var spinner = new ConsoleSpinner("Copying files"))
        {
            // Simulate file copy
            Thread.Sleep(3000);
        }

        Console.WriteLine("✓ Backup completed!");
    }
}

using ByteForge.Toolkit.CommandLine;

public class ProcessCommands
{
    [Command("process", "Process data files")]
    public static void Process(
        [Option("Input file")] string input)
    {
        // Create spinner with custom style and color
        var spinner = new ConsoleSpinner("Starting", SpinnerStyle.Braille, ConsoleColor.Cyan);

        try
        {
            // Update message dynamically
            for (int i = 1; i <= 5; i++)
            {
                spinner.Message = $"Processing step {i}/5";
                Thread.Sleep(1000);
            }

            spinner.Color = ConsoleColor.Green;
            spinner.Message = "Finalizing";
            Thread.Sleep(1000);
        }
        finally
        {
            spinner.Dispose();
        }

        Console.WriteLine("✓ Processing complete!");
    }
}

