using ByteForge.Toolkit.CommandLine;

// Basic spinner usage
public class SpinnerExample
{
    public static void Main()
  {
        // Simple spinner at current position
        var spinner = new ConsoleSpinner();
        spinner.Start();

      // Simulate work
        Thread.Sleep(3000);

        spinner.Stop();
        Console.WriteLine("✓ Done!");
    }
}

// Spinner with message
public class SpinnerWithMessage
{
    public static void Main()
    {
 using (var spinner = new ConsoleSpinner("Processing data"))
        {
            // Spinner automatically starts
            Thread.Sleep(2000);

    // Update message dynamically
 spinner.Message = "Almost done";
       Thread.Sleep(2000);

        } // Spinner automatically stops when disposed

        Console.WriteLine("✓ Processing complete!");
    }
}

// Colored spinner at specific position
public class ColoredSpinner
{
    public static void Main()
    {
        var spinner = new ConsoleSpinner(
            positionX: 0,
      positionY: 5,
message: "Loading",
          color: ConsoleColor.Cyan,
            style: SpinnerStyle.Dots,
          delay: 100);

        spinner.Start();
        Thread.Sleep(3000);
        spinner.Stop();
    }
}

