// Dynamic message updates
public class DynamicSpinnerMessages
{
    public static void Main()
    {
        var spinner = new ConsoleSpinner("Starting");
        spinner.Color = ConsoleColor.Yellow;

  try
        {
            spinner.Start();

for (int i = 1; i <= 10; i++)
            {
      spinner.Message = $"Processing item {i}/10";
Thread.Sleep(500);
    }

            spinner.Color = ConsoleColor.Green;
          spinner.Message = "Finalizing";
         Thread.Sleep(1000);
        }
        finally
        {
 spinner.Stop();
        }

        Console.WriteLine("✓ Complete!");
    }
}

// Integration with command
[Command("download", "Download files from server")]
public class DownloadCommand
{
    public static async Task Execute(
        [Option("File URL to download")] string url,
     [Option("Output file path")] string output)
    {
        using (var spinner = new ConsoleSpinner($"Downloading {url}"))
        {
            spinner.Color = ConsoleColor.Cyan;

// Simulate download
 for (int i = 0; i <= 100; i += 10)
            {
       spinner.Message = $"Downloading {url} ({i}%)";
        await Task.Delay(300);
     }
        }

        Console.WriteLine($"✓ Downloaded to {output}");
    }
}

using ByteForge.Toolkit.CommandLine;

public class GlobalOptionsExample
{
    public static void ConfigureGlobalOptions(RootCommandBuilder builder)
    {
        // Simple flag option (no value expected)
        builder.AddGlobalOption(
            "verbose",
            "Enable verbose logging",
            () => Console.WriteLine("Verbose mode enabled"),
            "v");

        // Option that expects a value
        builder.AddGlobalOption(
            "config",
            "Path to configuration file",
            (configPath) => 
            {
                Environment.SetEnvironmentVariable("CONFIG_FILE", configPath);
                Console.WriteLine($"Using config file: {configPath}");
            },
            "c", "cfg");

        // Debug level option with value
        builder.AddGlobalOption(
            "debug-level",
            "Set debug level (1-5)",
            (level) => 
            {
                if (int.TryParse(level, out int debugLevel))
                    Environment.SetEnvironmentVariable("DEBUG_LEVEL", level);
                else
                    Console.WriteLine($"Invalid debug level: {level}");
            },
            "d");
    }
}

// Usage examples:
// app.exe --verbose command
// app.exe -v command  
// app.exe --config myconfig.json command
// app.exe -c myconfig.json command
// app.exe --debug-level 3 command
// app.exe -d 2 command

using ByteForge.Toolkit.CommandLine;

public class GlobalOptionsExample
{
    private static bool _verboseMode = false;
    private static string? _configFile = null;

    public static int Main(string[] args)
    {
        var builder = new RootCommandBuilder("App with Global Options");

        // Boolean global option (no value expected)
 builder.AddGlobalOption(new GlobalOption(
    "verbose",
        "Enable verbose logging output",
      () => 
            {
        _verboseMode = true;
      Console.WriteLine("[VERBOSE] Verbose mode enabled");
     },
        expectsValue: false,
  "v", "verb"));

        // Global option with value
        builder.AddGlobalOption(new GlobalOption(
            "config",
            "Path to configuration file",
            (value) =>
  {
        _configFile = value;
 Console.WriteLine($"[CONFIG] Using configuration: {value}");
    // Load configuration
        LoadConfiguration(value);
            },
  expectsValue: true,
            "c", "cfg"));

        // Global option for environment
  builder.AddGlobalOption(new GlobalOption(
            "environment",
          "Set execution environment (dev/staging/prod)",
         (env) =>
  {
       Environment.SetEnvironmentVariable("APP_ENVIRONMENT", env);
   Console.WriteLine($"[ENV] Environment set to: {env}");
          },
       expectsValue: true,
   "env", "e"));

        // Global option for output format
      builder.AddGlobalOption(new GlobalOption(
            "output-format",
 "Set output format (json/xml/text)",
          (format) =>
   {
      Environment.SetEnvironmentVariable("OUTPUT_FORMAT", format);
           Console.WriteLine($"[FORMAT] Output format: {format}");
            },
     expectsValue: true,
  "format", "f"));

      // Global help option (custom implementation)
        builder.AddGlobalOption(new GlobalOption(
         "version",
       "Display application version information",
            () =>
   {
     var version = Assembly.GetExecutingAssembly().GetName().Version;
          var product = Assembly.GetExecutingAssembly()
        .GetCustomAttribute<AssemblyProductAttribute>()?.Product;
       Console.WriteLine($"{product} v{version}");
      Environment.Exit(0);
   },
            expectsValue: false,
          "ver", "v"));

     // Add commands
        builder.AddAssembly(typeof(GlobalOptionsExample).Assembly);

        var parser = builder.Build();
        var result = parser.Parse(args);

        return result.Invoke();
    }

    private static void LoadConfiguration(string path)
 {
        if (File.Exists(path))
            Console.WriteLine($"Configuration loaded from: {path}");
        else
            Console.WriteLine($"Warning: Configuration file not found: {path}");
}
}

