// In configuration file:
// [Data Source]
// SelectedDB = Production
// 
// [Production]
// sType=SQLServer
// sServer=ProdServer
// ...

var rootOptions = Configuration.Default.GetSection<DatabaseRootOptions>("Database");
var dbOptions = Configuration.Default.GetSection<DatabaseOptions>(rootOptions.SelectedDatabase);

var dbAccess = new DBAccess();
var script = @"
    SELECT * FROM Customers WHERE Country = 'USA';
    GO
    UPDATE Products SET Price = Price * 1.1 WHERE Category = 'Electronics';
    GO
    SELECT * FROM Products WHERE Category = 'Electronics';
";

var result = dbAccess.ExecuteScript(script);

if (result.Success)
{
    // Access the first result set (USA customers)
    if (result.ResultSets.Count > 0)
    {
        var usaCustomers = result.ResultSets[0];
        Console.WriteLine($"Found {usaCustomers.Rows.Count} USA customers");
    }

    // Check how many products were updated
    if (result.RecordsAffected.Count > 1)
    {
        var updatedCount = result.RecordsAffected[1];
        Console.WriteLine($"Updated {updatedCount} electronics products");
    }

    // Access the second result set (updated electronics products)
    if (result.ResultSets.Count > 1)
    {
        var updatedProducts = result.ResultSets[1];
        Console.WriteLine($"Retrieved {updatedProducts.Rows.Count} updated products");
    }
}
else
{
    Console.WriteLine($"Script execution failed: {result.LastException.Message}");
}

using ByteForge.Toolkit;
using Newtonsoft.Json;
using Newtonsoft.Json.Serialization;

// Advanced delta contract resolver with custom filtering
public class AdvancedDeltaResolver : DeltaContractResolver
{
    private readonly HashSet<string> _excludedProperties = new();
    private readonly Dictionary<Type, Func<object, object, bool>> _customComparers = new();

    public void ExcludeProperty(string propertyName)
    {
        _excludedProperties.Add(propertyName);
    }

    public void SetCustomComparer<T>(Func<T, T, bool> comparer) where T : class
    {
        _customComparers[typeof(T)] = (a, b) => comparer(a as T, b as T);
    }

    protected override JsonProperty CreateProperty(MemberInfo member, MemberSerialization memberSerialization)
    {
        var property = base.CreateProperty(member, memberSerialization);

        // Skip excluded properties
        if (_excludedProperties.Contains(property.PropertyName))
        {
            property.ShouldSerialize = _ => false;
            return property;
        }

        // Apply custom comparison logic
        var originalShouldSerialize = property.ShouldSerialize;
        property.ShouldSerialize = instance =>
        {
            // Call base logic first
            if (originalShouldSerialize?.Invoke(instance) == false)
                return false;

            // Apply custom comparer if available
            if (_customComparers.TryGetValue(instance.GetType(), out var comparer))
            {
                // Custom comparison logic here
                return true; // Simplified for example
            }

            return true;
        };

        return property;
    }
}

// Example usage with complex object types
public class Order
{
    public int OrderId { get; set; }
    public DateTime OrderDate { get; set; }
    public Customer Customer { get; set; }
    public List<OrderItem> Items { get; set; } = new();
    public decimal Total { get; set; }
    public OrderStatus Status { get; set; }
    public string InternalNotes { get; set; }  // Should not be serialized
    public DateTime LastModified { get; set; }
    public string ProcessingMetadata { get; set; }  // Should be excluded in deltas
}

public class OrderItem
{
    public int ProductId { get; set; }
    public string ProductName { get; set; }
    public int Quantity { get; set; }
    public decimal UnitPrice { get; set; }
    public decimal LineTotal => Quantity * UnitPrice;
}

public enum OrderStatus
{
    Pending,
    Processing,
    Shipped,
    Delivered,
    Cancelled
}

// Advanced delta serialization service
public class AdvancedDeltaService
{
    private readonly AdvancedDeltaResolver _resolver;
    private readonly JsonSerializerSettings _deltaSettings;
    private readonly JsonSerializerSettings _fullSettings;

    public AdvancedDeltaService()
    {
        _resolver = new AdvancedDeltaResolver();

        // Exclude internal properties from delta serialization
        _resolver.ExcludeProperty("InternalNotes");
        _resolver.ExcludeProperty("ProcessingMetadata");

        // Set up custom comparers
        _resolver.SetCustomComparer<Customer>((c1, c2) => 
            c1.Name == c2.Name && c1.Email == c2.Email);

        _deltaSettings = new JsonSerializerSettings
        {
            ContractResolver = _resolver,
            NullValueHandling = NullValueHandling.Ignore,
            Formatting = Formatting.None,
            DateFormatString = "yyyy-MM-ddTHH:mm:ssZ"
        };

        _fullSettings = new JsonSerializerSettings
        {
            Formatting = Formatting.Indented,
            DateFormatString = "yyyy-MM-ddTHH:mm:ssZ"
        };
    }

    public string SerializeOrderDelta(Order current, Order original)
    {
        // Configure resolver with original object
        _resolver.SetOriginalObject(original);

        // Serialize delta
        string deltaJson = JsonConvert.SerializeObject(current, _deltaSettings);

        return deltaJson;
    }

    public string SerializeFullOrder(Order order)
    {
        return JsonConvert.SerializeObject(order, _fullSettings);
    }

    public Order DeserializeOrderDelta(Order original, string deltaJson)
    {
        // Create a deep copy of the original
        var originalJson = SerializeFullOrder(original);
        var workingCopy = JsonConvert.DeserializeObject<Order>(originalJson, _fullSettings);

        // Apply delta changes
        JsonConvert.PopulateObject(deltaJson, workingCopy, _deltaSettings);

        // Update LastModified
        workingCopy.LastModified = DateTime.UtcNow;

        return workingCopy;
    }
}

// Demonstration of advanced delta serialization
public class AdvancedDeltaDemo
{
    public static void RunDemo()
    {
        var deltaService = new AdvancedDeltaService();

        // Create complex original order
        var originalOrder = new Order
        {
            OrderId = 1001,
            OrderDate = DateTime.Now.AddDays(-1),
            Customer = new Customer
            {
                Id = 123,
                Name = "John Smith",
                Email = "john@example.com",
                Phone = "555-1234",
                Address = "123 Main St",
                IsActive = true
            },
            Items = new List<OrderItem>
            {
                new OrderItem { ProductId = 1, ProductName = "Widget A", Quantity = 2, UnitPrice = 10.00m },
                new OrderItem { ProductId = 2, ProductName = "Widget B", Quantity = 1, UnitPrice = 15.00m }
            },
            Status = OrderStatus.Pending,
            InternalNotes = "Priority customer - expedite",
            ProcessingMetadata = "Queue: standard, Batch: 2024-001",
            LastModified = DateTime.Now.AddDays(-1)
        };

        originalOrder.Total = originalOrder.Items.Sum(i => i.LineTotal);

        Console.WriteLine("Original Order:");
        string fullJson = deltaService.SerializeFullOrder(originalOrder);
        Console.WriteLine(fullJson);
        Console.WriteLine($"Full size: {fullJson.Length} characters\n");

        // Modify order (customer email, add item, change status)
        var modifiedOrder = new Order
        {
            OrderId = 1001,
            OrderDate = originalOrder.OrderDate,
            Customer = new Customer
            {
                Id = 123,
                Name = "John Smith",
                Email = "john.smith@example.com",  // Email changed
                Phone = "555-1234",
                Address = "123 Main St",
                IsActive = true
            },
            Items = new List<OrderItem>
            {
                new OrderItem { ProductId = 1, ProductName = "Widget A", Quantity = 2, UnitPrice = 10.00m },
                new OrderItem { ProductId = 2, ProductName = "Widget B", Quantity = 1, UnitPrice = 15.00m },
                new OrderItem { ProductId = 3, ProductName = "Widget C", Quantity = 3, UnitPrice = 8.00m }  // Added item
            },
            Status = OrderStatus.Processing,  // Status changed
            InternalNotes = "Priority customer - expedite - processing started",
            ProcessingMetadata = "Queue: expedite, Batch: 2024-002",  // This should be excluded
            LastModified = DateTime.Now
        };

        modifiedOrder.Total = modifiedOrder.Items.Sum(i => i.LineTotal);

        // Generate delta
        string deltaJson = deltaService.SerializeOrderDelta(modifiedOrder, originalOrder);
        Console.WriteLine("Delta JSON (only changes):");
        Console.WriteLine(deltaJson);
        Console.WriteLine($"Delta size: {deltaJson.Length} characters");

        // Calculate compression
        double compression = (double)deltaJson.Length / fullJson.Length;
        Console.WriteLine($"Compression ratio: {compression:P1}");
        Console.WriteLine($"Size reduction: {(1 - compression):P1}\n");

        // Deserialize delta back to full object
        var reconstructed = deltaService.DeserializeOrderDelta(originalOrder, deltaJson);

        Console.WriteLine("Reconstructed Order:");
        string reconstructedJson = deltaService.SerializeFullOrder(reconstructed);
        Console.WriteLine(reconstructedJson);

        // Verify reconstruction
        Console.WriteLine("\nVerification:");
        Console.WriteLine($"Original total: ${originalOrder.Total:F2}");
        Console.WriteLine($"Modified total: ${modifiedOrder.Total:F2}");
        Console.WriteLine($"Reconstructed total: ${reconstructed.Total:F2}");
        Console.WriteLine($"Totals match: {modifiedOrder.Total == reconstructed.Total}");
        Console.WriteLine($"Status match: {modifiedOrder.Status == reconstructed.Status}");
        Console.WriteLine($"Email match: {modifiedOrder.Customer.Email == reconstructed.Customer.Email}");
        Console.WriteLine($"Items count match: {modifiedOrder.Items.Count == reconstructed.Items.Count}");

        // Show that excluded properties were not serialized
        Console.WriteLine($"\nExcluded properties verification:");
        Console.WriteLine($"ProcessingMetadata in delta: {deltaJson.Contains("ProcessingMetadata")}");
        Console.WriteLine($"InternalNotes in delta: {deltaJson.Contains("InternalNotes")}");
    }
}

// Run the demonstration
AdvancedDeltaDemo.RunDemo();

