// Enterprise API service using delta serialization
public class CustomerApiService
{
    private readonly JsonDeltaSerializer _deltaSerializer;
    private readonly Dictionary<int, Customer> _cache;

    public CustomerApiService()
    {
        _deltaSerializer = new JsonDeltaSerializer();
        _cache = new Dictionary<int, Customer>();
    }

    // GET endpoint - returns full customer data
    public ApiResponse GetCustomer(int customerId)
    {
        var customer = GetCustomerFromDatabase(customerId);

        // Cache the customer for future delta operations
        _cache[customerId] = CloneCustomer(customer);

        return new ApiResponse
        {
            Data = JsonConvert.SerializeObject(customer),
            IsPartial = false,
            Timestamp = DateTime.UtcNow
        };
    }

    // PUT endpoint - returns only changed properties
    public ApiResponse UpdateCustomer(int customerId, Customer updates)
    {
        var existingCustomer = GetCustomerFromDatabase(customerId);
        var originalState = _cache.ContainsKey(customerId) 
            ? _cache[customerId] 
            : CloneCustomer(existingCustomer);

        // Apply updates
        ApplyUpdates(existingCustomer, updates);

        // Save to database
        SaveCustomerToDatabase(existingCustomer);

        // Generate delta response
        string deltaJson = _deltaSerializer.SerializeDelta(existingCustomer, originalState);

        // Update cache
        _cache[customerId] = CloneCustomer(existingCustomer);

        return new ApiResponse
        {
            Data = deltaJson,
            IsPartial = true,
            Timestamp = DateTime.UtcNow,
            ChangedProperties = _deltaSerializer.GetChangedProperties(existingCustomer, originalState).ToList()
        };
    }

    // Batch update with delta tracking
    public BatchApiResponse UpdateMultipleCustomers(Dictionary<int, Customer> updates)
    {
        var responses = new List<CustomerUpdateResult>();
        var totalDataSize = 0;
        var totalDeltaSize = 0;

        foreach (var kvp in updates)
        {
            int customerId = kvp.Key;
            var updateData = kvp.Value;

            var existing = GetCustomerFromDatabase(customerId);
            var original = _cache.ContainsKey(customerId) 
                ? _cache[customerId] 
                : CloneCustomer(existing);

            // Measure full vs delta sizes
            string fullJson = JsonConvert.SerializeObject(existing);
            totalDataSize += fullJson.Length;

            // Apply updates
            ApplyUpdates(existing, updateData);
            SaveCustomerToDatabase(existing);

            // Generate delta
            string deltaJson = _deltaSerializer.SerializeDelta(existing, original);
            totalDeltaSize += deltaJson.Length;

            responses.Add(new CustomerUpdateResult
            {
                CustomerId = customerId,
                DeltaData = deltaJson,
                ChangedProperties = _deltaSerializer.GetChangedProperties(existing, original).ToList(),
                FullSizeBytes = fullJson.Length,
                DeltaSizeBytes = deltaJson.Length
            });

            _cache[customerId] = CloneCustomer(existing);
        }

        return new BatchApiResponse
        {
            Results = responses,
            TotalUpdated = responses.Count,
            TotalFullSizeBytes = totalDataSize,
            TotalDeltaSizeBytes = totalDeltaSize,
            CompressionRatio = (double)totalDeltaSize / totalDataSize,
            BandwidthSavings = totalDataSize - totalDeltaSize
        };
    }

    private void ApplyUpdates(Customer target, Customer updates)
    {
        if (updates.Name != null) target.Name = updates.Name;
        if (updates.Email != null) target.Email = updates.Email;
        if (updates.Phone != null) target.Phone = updates.Phone;
        if (updates.Address != null) target.Address = updates.Address;
        if (updates.IsActive != target.IsActive) target.IsActive = updates.IsActive;
        target.LastModified = DateTime.UtcNow;
    }

    private Customer CloneCustomer(Customer original)
    {
        return new Customer
        {
            Id = original.Id,
            Name = original.Name,
            Email = original.Email,
            Phone = original.Phone,
            Address = original.Address,
            LastModified = original.LastModified,
            IsActive = original.IsActive
        };
    }

    private Customer GetCustomerFromDatabase(int id)
    {
        // Simulate database retrieval
        return new Customer
        {
            Id = id,
            Name = "Sample Customer",
            Email = "customer@example.com",
            Phone = "555-0000",
            Address = "123 Sample St",
            LastModified = DateTime.Now.AddDays(-1),
            IsActive = true
        };
    }

    private void SaveCustomerToDatabase(Customer customer)
    {
        // Simulate database save
        Console.WriteLine($"Saved customer {customer.Id} to database");
    }
}

