// Change tracking interface and implementation
public interface IChangeTracker
{
    bool HasChanged(string propertyName);
    IEnumerable<string> GetChangedProperties();
    void ClearChanges();
    void MarkAsChanged(string propertyName);
}

// Enhanced customer class with change tracking
public class TrackableCustomer : IChangeTracker
{
    private readonly HashSet<string> _changedProperties = new();

    public int Id { get; set; }

    private string _name;
    public string Name
    {
        get => _name;
        set
        {
            if (_name != value)
            {
                _name = value;
                MarkAsChanged(nameof(Name));
            }
        }
    }

    private string _email;
    public string Email
    {
        get => _email;
        set
        {
            if (_email != value)
            {
                _email = value;
                MarkAsChanged(nameof(Email));
            }
        }
    }

    private string _phone;
    public string Phone
    {
        get => _phone;
        set
        {
            if (_phone != value)
            {
                _phone = value;
                MarkAsChanged(nameof(Phone));
            }
        }
    }

    private bool _isActive;
    public bool IsActive
    {
        get => _isActive;
        set
        {
            if (_isActive != value)
            {
                _isActive = value;
                MarkAsChanged(nameof(IsActive));
            }
        }
    }

    public DateTime LastModified { get; set; }

    // IChangeTracker implementation
    public bool HasChanged(string propertyName) => _changedProperties.Contains(propertyName);
    public IEnumerable<string> GetChangedProperties() => _changedProperties.ToList();
    public void ClearChanges() => _changedProperties.Clear();
    public void MarkAsChanged(string propertyName) => _changedProperties.Add(propertyName);
}

// Real-time sync service
public class RealTimeSyncService
{
    private readonly JsonDeltaSerializer _deltaSerializer;
    private readonly Dictionary<int, TrackableCustomer> _clientCache;
    private readonly Queue<SyncUpdate> _pendingUpdates;

    public RealTimeSyncService()
    {
        _deltaSerializer = new JsonDeltaSerializer();
        _clientCache = new Dictionary<int, TrackableCustomer>();
        _pendingUpdates = new Queue<SyncUpdate>();
    }

    // Simulate receiving update from server
    public void HandleServerUpdate(int customerId, string deltaJson)
    {
        Console.WriteLine($"Received server update for customer {customerId}");
        Console.WriteLine($"Delta: {deltaJson}");

        if (!_clientCache.TryGetValue(customerId, out var existingCustomer))
        {
            // First time seeing this customer - deserialize full object
            existingCustomer = JsonConvert.DeserializeObject<TrackableCustomer>(deltaJson);
            _clientCache[customerId] = existingCustomer;
            Console.WriteLine($"New customer cached: {customerId}");
        }
        else
        {
            // Merge delta with existing cached data
            var updated = _deltaSerializer.DeserializeDelta(existingCustomer, deltaJson);
            _clientCache[customerId] = updated;
            Console.WriteLine($"Customer {customerId} updated from delta");
        }

        // Clear change tracking after server sync
        _clientCache[customerId].ClearChanges();

        // Notify UI of update
        OnCustomerUpdated?.Invoke(customerId, _clientCache[customerId]);
    }

    // Handle local changes and prepare for server sync
    public void HandleLocalChange(int customerId)
    {
        if (!_clientCache.TryGetValue(customerId, out var customer))
            return;

        var changedProperties = customer.GetChangedProperties().ToList();
        if (!changedProperties.Any())
            return;

        Console.WriteLine($"Local changes detected for customer {customerId}:");
        foreach (var prop in changedProperties)
        {
            Console.WriteLine($"  - {prop}");
        }

        // Create delta for server sync
        var deltaJson = _deltaSerializer.SerializeDelta(customer, customer);

        var update = new SyncUpdate
        {
            CustomerId = customerId,
            DeltaJson = deltaJson,
            Timestamp = DateTime.UtcNow,
            ChangedProperties = changedProperties
        };

        _pendingUpdates.Enqueue(update);
        Console.WriteLine($"Queued update for sync: {deltaJson}");
    }

    // Sync pending changes to server
    public async Task SyncPendingChanges()
    {
        Console.WriteLine($"Syncing {_pendingUpdates.Count} pending changes...");

        var syncBatch = new List<SyncUpdate>();

        // Drain pending updates
        while (_pendingUpdates.Any())
        {
            syncBatch.Add(_pendingUpdates.Dequeue());
        }

        if (!syncBatch.Any()) return;

        foreach (var update in syncBatch)
        {
            try
            {
                // Simulate server API call
                await SendUpdateToServer(update);

                // Clear changes after successful sync
                if (_clientCache.TryGetValue(update.CustomerId, out var customer))
                {
                    customer.ClearChanges();
                }

                Console.WriteLine($"✓ Synced customer {update.CustomerId}");
            }
            catch (Exception ex)
            {
                Console.WriteLine($"✗ Failed to sync customer {update.CustomerId}: {ex.Message}");

                // Re-queue failed update
                _pendingUpdates.Enqueue(update);
            }
        }
    }

    private async Task SendUpdateToServer(SyncUpdate update)
    {
        // Simulate network delay
        await Task.Delay(100);

        // Simulate API call
        Console.WriteLine($"  POST /api/customers/{update.CustomerId}/delta");
        Console.WriteLine($"  Body: {update.DeltaJson}");

        // Simulate occasional network failure
        if (new Random().Next(10) < 2)
        {
            throw new Exception("Network timeout");
        }
    }

    public void PrintCacheStatus()
    {
        Console.WriteLine("\n=== Cache Status ===");
        Console.WriteLine($"Cached customers: {_clientCache.Count}");
        Console.WriteLine($"Pending updates: {_pendingUpdates.Count}");

        foreach (var kvp in _clientCache)
        {
            var customer = kvp.Value;
            var changes = customer.GetChangedProperties().ToList();
            Console.WriteLine($"  Customer {kvp.Key}: {changes.Count} pending changes");

            if (changes.Any())
            {
                Console.WriteLine($"    Changed: {string.Join(", ", changes)}");
            }
        }
        Console.WriteLine();
    }

    public event Action<int, TrackableCustomer> OnCustomerUpdated;
}

// Supporting classes
public class SyncUpdate
{
    public int CustomerId { get; set; }
    public string DeltaJson { get; set; }
    public DateTime Timestamp { get; set; }
    public List<string> ChangedProperties { get; set; }
}

// Demonstration
public class RealTimeSyncDemo
{
    public static async Task RunDemo()
    {
        var syncService = new RealTimeSyncService();

        // Subscribe to customer updates
        syncService.OnCustomerUpdated += (id, customer) =>
        {
            Console.WriteLine($"UI notification: Customer {id} updated - {customer.Name}");
        };

        Console.WriteLine("=== Real-Time Sync Demo ===");

        // Simulate initial data from server
        string initialData = JsonConvert.SerializeObject(new TrackableCustomer
        {
            Id = 1,
            Name = "John Doe",
            Email = "john@example.com",
            Phone = "555-1234",
            IsActive = true
        });

        syncService.HandleServerUpdate(1, initialData);

        // Simulate local changes
        var customer = new TrackableCustomer
        {
            Id = 1,
            Name = "John Doe",
            Email = "john.doe@example.com",  // Changed
            Phone = "555-5678",             // Changed
            IsActive = true
        };

        Console.WriteLine("\nMaking local changes...");
        customer.Email = "john.doe@example.com";
        customer.Phone = "555-5678";

        // This would be called by the client cache
        syncService.HandleLocalChange(1);
        syncService.PrintCacheStatus();

        // Sync changes
        await syncService.SyncPendingChanges();
        syncService.PrintCacheStatus();

        // Simulate server update to same customer
        string serverUpdate = "{\"Name\":\"John D. Doe\",\"LastModified\":\"2024-01-15T14:30:00Z\"}";
        syncService.HandleServerUpdate(1, serverUpdate);
        syncService.PrintCacheStatus();
    }
}

// Run the demo
await RealTimeSyncDemo.RunDemo();

