async Task ProcessWebRequest(string method, string path)
{
    var requestId = Guid.NewGuid().ToString("N")[..8];

    // Create correlation context for the request
    using (var context = new CorrelationContext($"REQ-{requestId}"))
    {
        Log.Info($"Incoming request: {method} {path}");

        try
        {
            // Simulate request processing steps
            await ValidateRequest(method, path);
            await AuthenticateUser();
            await ProcessBusinessLogic(path);
            await GenerateResponse();

            Log.Info($"Request completed successfully: {method} {path}");
        }
        catch (Exception ex)
        {
            Log.Error($"Request failed: {method} {path}", ex);
            throw;
        }
    }
}

async Task ValidateRequest(string method, string path)
{
    Log.Debug("Starting request validation");

    // Simulate validation steps
    await Task.Delay(10);
    Log.Debug("Request headers validated");

    await Task.Delay(5);
    Log.Debug("Request body validated");

    if (path.Contains("invalid"))
    {
        throw new ArgumentException("Invalid path detected");
    }

    Log.Info("Request validation completed");
}

async Task AuthenticateUser()
{
    Log.Debug("Starting user authentication");

    // Simulate authentication
    await Task.Delay(20);
    Log.Debug("Checking authentication token");

    await Task.Delay(15);
    Log.Info("User authenticated successfully");
}

async Task ProcessBusinessLogic(string path)
{
    Log.Debug("Starting business logic processing");

    if (path.Contains("users"))
    {
        await ProcessUserOperation(path);
    }
    else if (path.Contains("orders"))
    {
        await ProcessOrderOperation();
    }
    else
    {
        Log.Warn($"Unknown operation for path: {path}");
    }

    Log.Info("Business logic processing completed");
}

async Task ProcessUserOperation(string path)
{
    Log.Debug("Processing user operation");

    if (path.Contains("profile"))
    {
        Log.Info("Updating user profile");
        await Task.Delay(30);
        Log.Debug("Profile validation completed");
        await Task.Delay(20);
        Log.Debug("Profile saved to database");
    }
    else
    {
        Log.Info("Retrieving user information");
        await Task.Delay(15);
        Log.Debug("User data loaded from database");
    }
}

async Task ProcessOrderOperation()
{
    Log.Debug("Processing order operation");
    Log.Info("Creating new order");

    await Task.Delay(25);
    Log.Debug("Inventory check completed");

    await Task.Delay(35);
    Log.Debug("Payment processing initiated");

    // Simulate potential error
    var random = new Random();
    if (random.Next(10) < 2) // 20% chance of error
    {
        throw new InvalidOperationException("Payment processing failed");
    }

    await Task.Delay(20);
    Log.Info("Order created successfully");
}

async Task GenerateResponse()
{
    Log.Debug("Generating response");

    await Task.Delay(10);
    Log.Debug("Response serialized");

    Log.Info("Response generated");
}

