// Advanced progress tracking with statistics and UI updates
public class TransferProgressMonitor
{
    private readonly List<ProgressSnapshot> _progressHistory;
    private readonly Timer _statsTimer;
    private DateTime _transferStartTime;
    private long _lastBytesTransferred;
    private DateTime _lastUpdateTime;

    public TransferProgressMonitor()
    {
        _progressHistory = new List<ProgressSnapshot>();
        _statsTimer = new Timer(DisplayStatistics, null, Timeout.Infinite, Timeout.Infinite);
    }

    public void StartMonitoring(FileTransferClient client)
    {
        _transferStartTime = DateTime.Now;
        _lastUpdateTime = _transferStartTime;
        _progressHistory.Clear();

        client.ProgressChanged += OnProgressChanged;
        client.TransferCompleted += OnTransferCompleted;

        // Update statistics every 2 seconds
        _statsTimer.Change(TimeSpan.FromSeconds(2), TimeSpan.FromSeconds(2));
    }

    private void OnProgressChanged(object sender, FileTransferProgress progress)
    {
        // Record progress snapshot
        var snapshot = new ProgressSnapshot
        {
            Timestamp = DateTime.Now,
            FileName = progress.FileName,
            TotalBytes = progress.TotalBytes,
            TransferredBytes = progress.TransferredBytes,
            PercentComplete = progress.PercentComplete,
            Speed = progress.Speed,
            ElapsedTime = progress.ElapsedTime,
            EstimatedTimeRemaining = progress.EstimatedTimeRemaining
        };

        _progressHistory.Add(snapshot);

        // Keep only last 100 snapshots to manage memory
        if (_progressHistory.Count > 100)
        {
            _progressHistory.RemoveAt(0);
        }

        // Calculate instantaneous speed
        var now = DateTime.Now;
        var timeDiff = (now - _lastUpdateTime).TotalSeconds;

        if (timeDiff >= 1.0) // Update every second
        {
            var bytesDiff = progress.TransferredBytes - _lastBytesTransferred;
            var instantSpeed = timeDiff > 0 ? bytesDiff / timeDiff : 0;

            // Display progress with enhanced information
            Console.Clear();
            Console.WriteLine("=== File Transfer Progress ===");
            Console.WriteLine($"File: {progress.FileName}");
            Console.WriteLine($"Progress: {progress.PercentComplete:P1}");
            Console.WriteLine($"Size: {FormatBytes(progress.TransferredBytes)} / {FormatBytes(progress.TotalBytes)}");
            Console.WriteLine($"Current Speed: {FormatBytes((long)instantSpeed)}/s");
            Console.WriteLine($"Average Speed: {FormatBytes((long)progress.Speed)}/s");
            Console.WriteLine($"Elapsed: {FormatTime(progress.ElapsedTime)}");
            Console.WriteLine($"Remaining: {FormatTime(progress.EstimatedTimeRemaining)}");
            Console.WriteLine();

            // Draw progress bar
            DrawProgressBar(progress.PercentComplete, 50);
            Console.WriteLine();

            // Show speed graph (last 10 data points)
            ShowSpeedGraph();

            _lastBytesTransferred = progress.TransferredBytes;
            _lastUpdateTime = now;
        }
    }

    private void OnTransferCompleted(object sender, FileTransferResult result)
    {
        _statsTimer.Change(Timeout.Infinite, Timeout.Infinite);

        Console.Clear();
        Console.WriteLine("=== Transfer Complete ===");

        if (result.IsSuccess)
        {
            var duration = result.Duration;
            var totalBytes = result.TransferedFiles.Sum(f => f.FileSize);
            var averageSpeed = totalBytes / duration.TotalSeconds;

            Console.WriteLine($"✓ Transfer successful!");
            Console.WriteLine($"Files transferred: {result.TransferedFiles.Count}");
            Console.WriteLine($"Total size: {FormatBytes(totalBytes)}");
            Console.WriteLine($"Duration: {FormatTime(duration)}");
            Console.WriteLine($"Average speed: {FormatBytes((long)averageSpeed)}/s");

            // Show final statistics
            ShowFinalStatistics();
        }
        else
        {
            Console.WriteLine($"✗ Transfer failed: {result.ErrorMessage}");
            Console.WriteLine($"Failed files: {result.FailedFiles.Count}");
        }
    }

    private void DrawProgressBar(double percentage, int width)
    {
        int completed = (int)(percentage * width);
        int remaining = width - completed;

        Console.Write("[");
        Console.Write(new string('█', completed));
        Console.Write(new string('░', remaining));
        Console.Write($"] {percentage:P1}");
    }

    private void ShowSpeedGraph()
    {
        if (_progressHistory.Count < 2) return;

        var recentSpeeds = _progressHistory
            .TakeLast(10)
            .Select(s => s.Speed)
            .ToList();

        if (!recentSpeeds.Any()) return;

        var maxSpeed = recentSpeeds.Max();
        var minSpeed = recentSpeeds.Min();

        Console.WriteLine("Speed History (last 10 samples):");

        for (int i = 0; i < recentSpeeds.Count; i++)
        {
            var speed = recentSpeeds[i];
            var percentage = maxSpeed > 0 ? speed / maxSpeed : 0;
            var barLength = (int)(percentage * 20);

            Console.WriteLine($"  {i + 1:D2}: {new string('▓', barLength),-20} {FormatBytes((long)speed)}/s");
        }
    }

    private void ShowFinalStatistics()
    {
        if (!_progressHistory.Any()) return;

        var speeds = _progressHistory.Select(s => s.Speed).ToList();
        var avgSpeed = speeds.Average();
        var maxSpeed = speeds.Max();
        var minSpeed = speeds.Where(s => s > 0).DefaultIfEmpty(0).Min();

        Console.WriteLine();
        Console.WriteLine("Transfer Statistics:");
        Console.WriteLine($"  Average Speed: {FormatBytes((long)avgSpeed)}/s");
        Console.WriteLine($"  Peak Speed: {FormatBytes((long)maxSpeed)}/s");
        Console.WriteLine($"  Minimum Speed: {FormatBytes((long)minSpeed)}/s");
        Console.WriteLine($"  Speed Variation: {(maxSpeed - minSpeed) / avgSpeed * 100:F1}%");
        Console.WriteLine($"  Samples Recorded: {_progressHistory.Count}");
    }

    private void DisplayStatistics(object state)
    {
        // This would update a separate statistics window or log
        if (_progressHistory.Any())
        {
            var latest = _progressHistory.Last();
            var logMessage = $"[{latest.Timestamp:HH:mm:ss}] {latest.FileName}: " +
                           $"{latest.PercentComplete:P1} at {FormatBytes((long)latest.Speed)}/s";

            // Log to file or send to monitoring system
            File.AppendAllText("transfer_log.txt", logMessage + Environment.NewLine);
        }
    }

    private string FormatBytes(long bytes)
    {
        string[] suffixes = { "B", "KB", "MB", "GB", "TB" };
        int counter = 0;
        decimal number = bytes;

        while (Math.Round(number / 1024) >= 1)
        {
            number /= 1024;
            counter++;
        }

        return $"{number:N1} {suffixes[counter]}";
    }

    private string FormatTime(TimeSpan time)
    {
        if (time.TotalDays >= 1)
            return $"{time.Days}d {time.Hours:D2}:{time.Minutes:D2}:{time.Seconds:D2}";
        else if (time.TotalHours >= 1)
            return $"{time.Hours:D2}:{time.Minutes:D2}:{time.Seconds:D2}";
        else
            return $"{time.Minutes:D2}:{time.Seconds:D2}";
    }
}

public class ProgressSnapshot
{
    public DateTime Timestamp { get; set; }
    public string FileName { get; set; }
    public long TotalBytes { get; set; }
    public long TransferredBytes { get; set; }
    public double PercentComplete { get; set; }
    public double Speed { get; set; }
    public TimeSpan ElapsedTime { get; set; }
    public TimeSpan EstimatedTimeRemaining { get; set; }
}

