// Simple logger implementation for example
public class ConsoleLogger : ILogger
{
    public void Debug(string message) => Console.WriteLine($"[DEBUG] {message}");
    public void Info(string message) => Console.WriteLine($"[INFO] {message}");
    public void Warning(string message) => Console.WriteLine($"[WARN] {message}");
    public void Error(string message, Exception ex = null) => Console.WriteLine($"[ERROR] {message}" + (ex != null ? $" - {ex.Message}" : ""));
    public void Fatal(string message, Exception ex = null) => Console.WriteLine($"[FATAL] {message}" + (ex != null ? $" - {ex.Message}" : ""));
}

public interface ILogger
{
    void Debug(string message);
    void Info(string message);
    void Warning(string message);
    void Error(string message, Exception ex = null);
    void Fatal(string message, Exception ex = null);
}

using ByteForge.Toolkit;
using System.Globalization;

var parser = new DateTimeParser();

// Standard date parsing
DateTime date1 = parser.Parse("2024-01-15");              // ISO format
DateTime date2 = parser.Parse("01/15/2024");              // US format
DateTime date3 = parser.Parse("15/01/2024");              // European format
DateTime date4 = parser.Parse("January 15, 2024");        // Long format

// Time parsing
DateTime time1 = parser.Parse("14:30:00");                // 24-hour
DateTime time2 = parser.Parse("2:30 PM");                 // 12-hour
DateTime time3 = parser.Parse("2:30:45.123 PM");          // With milliseconds

// Date and time combinations
DateTime dt1 = parser.Parse("2024-01-15 14:30:00");
DateTime dt2 = parser.Parse("January 15, 2024 2:30 PM");
DateTime dt3 = parser.Parse("15/01/2024 14:30");

// Relative date parsing
DateTime now = DateTime.Now;
DateTime yesterday = parser.ParseRelative("yesterday");
DateTime tomorrow = parser.ParseRelative("tomorrow");
DateTime nextWeek = parser.ParseRelative("next week");
DateTime lastMonth = parser.ParseRelative("last month");

// Culture-specific parsing
var frenchCulture = new CultureInfo("fr-FR");
var germanCulture = new CultureInfo("de-DE");

parser.SetCulture(frenchCulture);
DateTime frenchDate = parser.Parse("15 janvier 2024");

parser.SetCulture(germanCulture);
DateTime germanDate = parser.Parse("15. Januar 2024");

// Safe parsing with defaults
DateTime safe1 = parser.TryParse("invalid date", DateTime.MinValue);
DateTime safe2 = parser.TryParse("2024-01-15", DateTime.MinValue);
DateTime safe3 = parser.TryParse(null, DateTime.Now);

// Parse from various input sources
var dateInputs = new[]
{
    "2024-01-15",
    "01/15/2024",
    "15-Jan-2024",
    "Monday, January 15, 2024",
    "yesterday",
    "next Friday",
    "invalid",
    ""
};

Console.WriteLine("Date parsing results:");
foreach (var input in dateInputs)
{
    try
    {
        var parsed = parser.Parse(input);
        Console.WriteLine($"'{input}' -> {parsed:yyyy-MM-dd HH:mm:ss}");
    }
    catch (FormatException)
    {
        var fallback = parser.TryParse(input, DateTime.MinValue);
        Console.WriteLine($"'{input}' -> Could not parse (using fallback: {fallback:yyyy-MM-dd})");
    }
}

using ByteForge.Toolkit.Logging;
using System;
using System.IO;
using System.Threading.Tasks;

// Enterprise logging configuration service
public class LoggingService
{
    private readonly CompositeLogger _compositeLogger;
    private readonly FileLogger _applicationLogger;
    private readonly FileLogger _errorLogger;
    private readonly FileLogger _auditLogger;
    private readonly SessionFileLogger _sessionLogger;
    private readonly ConsoleLogger _consoleLogger;

    public LoggingService(string logDirectory = @"C:\Logs\MyApp")
    {
        Directory.CreateDirectory(logDirectory);

        // Configure different loggers for different purposes
        _consoleLogger = new ConsoleLogger();

        _applicationLogger = new FileLogger(new FileLoggerOptions
        {
            FilePath = Path.Combine(logDirectory, "application.log"),
            MaxFileSizeBytes = 20 * 1024 * 1024, // 20 MB
            MaxFileCount = 10,
            AutoFlush = false, // Better performance
            IncludeTimestamp = true,
            IncludeThreadId = true,
            DateTimeFormat = "yyyy-MM-dd HH:mm:ss.fff"
        });

        _errorLogger = new FileLogger(new FileLoggerOptions
        {
            FilePath = Path.Combine(logDirectory, "errors.log"),
            MaxFileSizeBytes = 10 * 1024 * 1024, // 10 MB
            MaxFileCount = 20, // Keep more error logs
            AutoFlush = true,  // Immediate write for errors
            IncludeTimestamp = true,
            IncludeLogLevel = true,
            IncludeThreadId = true
        });

        _auditLogger = new FileLogger(new FileLoggerOptions
        {
            FilePath = Path.Combine(logDirectory, "audit.log"),
            MaxFileSizeBytes = 50 * 1024 * 1024, // 50 MB
            MaxFileCount = 50, // Keep extensive audit trail
            AutoFlush = true,
            IncludeTimestamp = true
        });

        _sessionLogger = new SessionFileLogger(new SessionFileLoggerOptions
        {
            BaseDirectory = Path.Combine(logDirectory, "Sessions"),
            FileNameFormat = "session_{sessionId}_{timestamp:yyyyMMdd_HHmmss}.log",
            MaxFileSizeBytes = 5 * 1024 * 1024,
            MaxSessionFiles = 200,
            AutoCleanupOldSessions = true
        });

        // Create composite logger with appropriate levels
        _compositeLogger = new CompositeLogger();
        _compositeLogger.AddLogger(_consoleLogger, LogLevel.Information);
        _compositeLogger.AddLogger(_applicationLogger, LogLevel.Debug);
        _compositeLogger.AddLogger(_errorLogger, LogLevel.Warning);

        // Initialize static Log facade
        Log.Initialize(_compositeLogger);

        Log.Info("Logging service initialized");
        Log.Info($"Log directory: {logDirectory}");
    }

    public void LogAuditEvent(string userId, string action, object details = null)
    {
        var auditEntry = new
        {
            Timestamp = DateTime.UtcNow,
            UserId = userId,
            Action = action,
            Details = details,
            IPAddress = GetClientIPAddress(),
            UserAgent = GetUserAgent()
        };

        _auditLogger.Log(LogLevel.Information, $"AUDIT: {action}", auditEntry);
        Log.Debug($"Audit logged: {userId} - {action}");
    }

    public void StartUserSession(string userId, string sessionId)
    {
        _sessionLogger.StartSession(sessionId);
        _sessionLogger.Log(LogLevel.Information, $"Session started for user: {userId}");

        LogAuditEvent(userId, "SessionStarted", new { SessionId = sessionId });
    }

    public void EndUserSession(string userId, string sessionId)
    {
        _sessionLogger.Log(LogLevel.Information, $"Session ended for user: {userId}");
        _sessionLogger.EndSession(sessionId);

        LogAuditEvent(userId, "SessionEnded", new { SessionId = sessionId });
    }

    public async Task LogBusinessOperation(string operationType, string userId, Func<Task> operation)
    {
        var operationId = Guid.NewGuid().ToString("N")[..8];

        using (var context = new CorrelationContext($"OP-{operationId}"))
        {
            Log.Info($"Starting operation: {operationType}");
            LogAuditEvent(userId, $"OperationStarted", new { OperationType = operationType, OperationId = operationId });

            var stopwatch = System.Diagnostics.Stopwatch.StartNew();

            try
            {
                await operation();

                stopwatch.Stop();
                Log.Info($"Operation completed: {operationType} in {stopwatch.ElapsedMilliseconds}ms");
                LogAuditEvent(userId, $"OperationCompleted", new { 
                    OperationType = operationType, 
                    OperationId = operationId,
                    DurationMs = stopwatch.ElapsedMilliseconds
                });
            }
            catch (Exception ex)
            {
                stopwatch.Stop();
                Log.Error($"Operation failed: {operationType} in {stopwatch.ElapsedMilliseconds}ms", ex);
                LogAuditEvent(userId, $"OperationFailed", new { 
                    OperationType = operationType, 
                    OperationId = operationId,
                    DurationMs = stopwatch.ElapsedMilliseconds,
                    Error = ex.Message
                });
                throw;
            }
        }
    }

    public void LogPerformanceMetrics(string operation, TimeSpan duration, Dictionary<string, object> metrics = null)
    {
        var performanceData = new
        {
            Operation = operation,
            DurationMs = duration.TotalMilliseconds,
            Timestamp = DateTime.UtcNow,
            Metrics = metrics ?? new Dictionary<string, object>()
        };

        if (duration.TotalSeconds > 5)
        {
            Log.Warn($"Slow operation detected: {operation} took {duration.TotalSeconds:F2}s", performanceData);
        }
        else if (duration.TotalSeconds > 1)
        {
            Log.Info($"Performance: {operation} took {duration.TotalMilliseconds:F0}ms", performanceData);
        }
        else
        {
            Log.Debug($"Performance: {operation} took {duration.TotalMilliseconds:F0}ms", performanceData);
        }
    }

    private string GetClientIPAddress()
    {
        // In a real application, get from HttpContext
        return "192.168.1.100";
    }

    private string GetUserAgent()
    {
        // In a real application, get from HttpContext
        return "MyApp/1.0.0";
    }

    public void Dispose()
    {
        Log.Info("Logging service shutting down");

        _applicationLogger?.Dispose();
        _errorLogger?.Dispose();
        _auditLogger?.Dispose();
        _sessionLogger?.Dispose();
        _consoleLogger?.Dispose();
    }
}

// Sample business service that uses logging
public class UserService
{
    private readonly LoggingService _loggingService;

    public UserService(LoggingService loggingService)
    {
        _loggingService = loggingService;
    }

    public async Task<User> GetUserAsync(int userId)
    {
        await _loggingService.LogBusinessOperation("GetUser", userId.ToString(), async () =>
        {
            Log.Debug($"Loading user from database: {userId}");

            // Simulate database operation
            await Task.Delay(100);

            Log.Debug($"User data retrieved: {userId}");
        });

        return new User { Id = userId, Name = $"User {userId}", Email = $"user{userId}@example.com" };
    }

    public async Task CreateUserAsync(User user)
    {
        await _loggingService.LogBusinessOperation("CreateUser", user.Email, async () =>
        {
            Log.Info($"Creating new user: {user.Email}");

            // Validate user data
            if (string.IsNullOrEmpty(user.Email))
            {
                throw new ArgumentException("Email is required");
            }

            Log.Debug("User validation completed");

            // Simulate database save
            await Task.Delay(200);

            Log.Info($"User created successfully: {user.Email}");
        });

        _loggingService.LogAuditEvent("system", "UserCreated", new 
        { 
            UserId = user.Id, 
            Email = user.Email, 
            Name = user.Name 
        });
    }

    public async Task UpdateUserProfileAsync(int userId, UserProfile profile)
    {
        var stopwatch = System.Diagnostics.Stopwatch.StartNew();

        try
        {
            await _loggingService.LogBusinessOperation("UpdateUserProfile", userId.ToString(), async () =>
            {
                Log.Info($"Updating profile for user: {userId}");

                // Validate profile data
                Log.Debug("Validating profile data");
                await Task.Delay(50);

                // Save to database
                Log.Debug("Saving profile to database");
                await Task.Delay(150);

                // Update cache
                Log.Debug("Updating user cache");
                await Task.Delay(30);

                Log.Info($"Profile updated successfully for user: {userId}");
            });

            _loggingService.LogAuditEvent(userId.ToString(), "ProfileUpdated", profile);
        }
        finally
        {
            stopwatch.Stop();
            _loggingService.LogPerformanceMetrics("UpdateUserProfile", stopwatch.Elapsed, 
                new Dictionary<string, object> 
                { 
                    { "UserId", userId }, 
                    { "ProfileSize", profile?.ToString()?.Length ?? 0 } 
                });
        }
    }
}

