}

// Main application demonstrating enterprise logging
public class Application
{
    private LoggingService _loggingService;
    private UserService _userService;

    public async Task RunAsync()
    {
        // Initialize logging
        _loggingService = new LoggingService();
        _userService = new UserService(_loggingService);

        try
        {
            Log.Info("Application starting");

            // Simulate user sessions and operations
            await SimulateUserSessions();

            Log.Info("Application completed successfully");
        }
        catch (Exception ex)
        {
            Log.Fatal("Application crashed", ex);
            throw;
        }
        finally
        {
            _loggingService?.Dispose();
        }
    }

    private async Task SimulateUserSessions()
    {
        var users = new[]
        {
            new { Id = 1, Email = "john.doe@company.com", SessionId = Guid.NewGuid().ToString() },
            new { Id = 2, Email = "jane.smith@company.com", SessionId = Guid.NewGuid().ToString() },
            new { Id = 3, Email = "bob.johnson@company.com", SessionId = Guid.NewGuid().ToString() }
        };

        var tasks = users.Select(async user =>
        {
            // Start user session
            _loggingService.StartUserSession(user.Id.ToString(), user.SessionId);

            try
            {
                // Get user data
                var userData = await _userService.GetUserAsync(user.Id);

                // Update profile
                var profile = new UserProfile
                {
                    FirstName = userData.Name.Split(' ')[0],
                    LastName = userData.Name.Split(' ').LastOrDefault(),
                    PhoneNumber = $"555-{1000 + user.Id}"
                };

                await _userService.UpdateUserProfileAsync(user.Id, profile);

                // Simulate some user activity
                for (int i = 0; i < 5; i++)
                {
                    Log.Debug($"User {user.Id} performed action {i + 1}");
                    await Task.Delay(100);
                }
            }
            catch (Exception ex)
            {
                Log.Error($"Error in user session {user.Id}", ex);
            }
            finally
            {
                // End user session
                _loggingService.EndUserSession(user.Id.ToString(), user.SessionId);
            }
        });

        await Task.WhenAll(tasks);
    }
}

