        foreach (var kvp in config)
        {
            Console.WriteLine($"  {kvp.Key}: {kvp.Value}");
        }

        // Encrypt sensitive values
        var encryptedConfig = _security.EncryptConfigurationSection(config);

        Console.WriteLine("\nEncrypted configuration:");
        foreach (var kvp in encryptedConfig)
        {
            Console.WriteLine($"  {kvp.Key}: {kvp.Value}");
        }

        // Decrypt for use
