using ByteForge.Toolkit;

// Create a binary search tree for integers
var bst = new BinarySearchTree<int>();

// Insert values
bst.Insert(50);
bst.Insert(30);
bst.Insert(70);
bst.Insert(20);
bst.Insert(40);
bst.Insert(60);
bst.Insert(80);

Console.WriteLine($"Tree size: {bst.Count}");

// Search for values
bool contains40 = bst.Contains(40);  // true
bool contains90 = bst.Contains(90);  // false
Console.WriteLine($"Contains 40: {contains40}");
Console.WriteLine($"Contains 90: {contains90}");

// Find min and max values
int minValue = bst.FindMin();  // 20
int maxValue = bst.FindMax();  // 80
Console.WriteLine($"Min value: {minValue}");
Console.WriteLine($"Max value: {maxValue}");

// In-order traversal (sorted order)
Console.WriteLine("In-order traversal:");
foreach (var value in bst.InOrderTraversal())
{
    Console.Write($"{value} ");  // 20 30 40 50 60 70 80
}
Console.WriteLine();

// Remove values
bst.Remove(30);
bst.Remove(70);

Console.WriteLine($"After removal, tree size: {bst.Count}");
