// Performance test: BST vs List for sorted data
var random = new Random(12345); // Fixed seed for reproducible results
var testData = Enumerable.Range(1, 10000)
    .Select(i => random.Next(1, 100000))
    .ToArray();

// Test BST performance
var stopwatch = Stopwatch.StartNew();
var bst = new BinarySearchTree<int>();

foreach (var value in testData)
{
    bst.Insert(value);
}
stopwatch.Stop();
Console.WriteLine($"BST insertion of {testData.Length} items: {stopwatch.ElapsedMilliseconds}ms");

// Test search performance
stopwatch.Restart();
int foundCount = 0;
for (int i = 0; i < 1000; i++)
{
    if (bst.Contains(random.Next(1, 100000)))
        foundCount++;
}
stopwatch.Stop();
Console.WriteLine($"BST search 1000 times: {stopwatch.ElapsedMilliseconds}ms ({foundCount} found)");

// Test List performance for comparison
stopwatch.Restart();
var list = new List<int>(testData);
list.Sort();
stopwatch.Stop();
Console.WriteLine($"List sort of {testData.Length} items: {stopwatch.ElapsedMilliseconds}ms");

stopwatch.Restart();
foundCount = 0;
for (int i = 0; i < 1000; i++)
{
    if (list.BinarySearch(random.Next(1, 100000)) >= 0)
        foundCount++;
}
stopwatch.Stop();
Console.WriteLine($"List binary search 1000 times: {stopwatch.ElapsedMilliseconds}ms ({foundCount} found)");

// Display tree statistics
Console.WriteLine($"\nBST Statistics:");
Console.WriteLine($"  Total nodes: {bst.Count}");
Console.WriteLine($"  Tree height: {bst.Height}");
Console.WriteLine($"  Is balanced: {bst.IsBalanced()}");

// Bulk operations
var valuesToRemove = testData.Take(1000).ToArray();
stopwatch.Restart();
foreach (var value in valuesToRemove)
{
    bst.Remove(value);
}
stopwatch.Stop();
Console.WriteLine($"BST removal of {valuesToRemove.Length} items: {stopwatch.ElapsedMilliseconds}ms");
Console.WriteLine($"Remaining nodes: {bst.Count}");

public class LoggingConfig : ConfigSection<LoggingConfig>
{
    public string LogLevel { get; set; } = "Info";

    [DefaultValueProvider(nameof(GetDefaultLogPath))]
    public string LogFilePath { get; set; }

    [DefaultValueProvider(nameof(GetDefaultMaxSize))]
    public long MaxFileSizeMB { get; set; }

    public bool EnableRotation { get; set; } = true;

    // Static method to provide dynamic defaults
    public static string GetDefaultLogPath()
    {
        var appName = Assembly.GetEntryAssembly()?.GetName().Name ?? "Application";
        var logDir = Path.Combine(Environment.GetFolderPath(Environment.SpecialFolder.LocalApplicationData), appName, "Logs");
        Directory.CreateDirectory(logDir);
        return Path.Combine(logDir, $"{appName}.log");
    }

    public static long GetDefaultMaxSize()
    {
        // Default to 10MB, but larger on servers with more disk space
        var drives = DriveInfo.GetDrives().Where(d => d.IsReady);
        var availableSpace = drives.Sum(d => d.AvailableFreeSpace);

        // If more than 100GB available, use 50MB default
        return availableSpace > 100L * 1024 * 1024 * 1024 ? 50 : 10;
    }
}

