using ByteForge.Toolkit;
using System;
using System.Collections.Concurrent;
using System.Collections.Generic;
using System.IO;
using System.Linq;
using System.Threading;
using System.Threading.Tasks;

// Enterprise file transfer service with queue management and monitoring
public class EnterpriseFileTransferService
{
    private readonly ConcurrentQueue<TransferJob> _transferQueue;
    private readonly ConcurrentDictionary<string, FileTransferClient> _activeClients;
    private readonly List<TransferJobResult> _transferHistory;
    private readonly SemaphoreSlim _concurrencyLimiter;
    private readonly ILogger _logger;
    private readonly FileTransferServiceConfig _config;
    private readonly CancellationTokenSource _cancellationTokenSource;
    private readonly Task _processingTask;

    public EnterpriseFileTransferService(ILogger logger, FileTransferServiceConfig config)
    {
        _logger = logger;
        _config = config;
        _transferQueue = new ConcurrentQueue<TransferJob>();
        _activeClients = new ConcurrentDictionary<string, FileTransferClient>();
        _transferHistory = new List<TransferJobResult>();
        _concurrencyLimiter = new SemaphoreSlim(config.MaxConcurrentTransfers, config.MaxConcurrentTransfers);
        _cancellationTokenSource = new CancellationTokenSource();

        // Start background processing
        _processingTask = Task.Run(ProcessTransferQueue, _cancellationTokenSource.Token);

        _logger.Info($"Enterprise File Transfer Service started with {config.MaxConcurrentTransfers} concurrent transfers");
    }

    public string QueueTransfer(TransferJob job)
    {
        job.Id = Guid.NewGuid().ToString();
        job.QueuedAt = DateTime.UtcNow;
        job.Status = TransferJobStatus.Queued;

        _transferQueue.Enqueue(job);
        _logger.Info($"Transfer job queued: {job.Id} - {job.Description}");

        return job.Id;
    }

    public string QueueBatchUpload(string description, Dictionary<string, string> fileMapping, FileTransferConfig config)
    {
        var items = fileMapping.Select(kvp => new FileTransferItem
        {
            SourcePath = kvp.Key,
            DestinationPath = kvp.Value,
            FileName = Path.GetFileName(kvp.Key),
            Overwrite = true
        }).ToList();

        var job = new TransferJob
        {
            Description = description,
            Type = TransferJobType.BatchUpload,
            Config = config,
            Items = items,
            Priority = TransferPriority.Normal
        };

        return QueueTransfer(job);
    }

    public string QueueBatchDownload(string description, Dictionary<string, string> fileMapping, FileTransferConfig config)
    {
        var items = fileMapping.Select(kvp => new FileTransferItem
        {
            SourcePath = kvp.Key,
            DestinationPath = kvp.Value,
            FileName = Path.GetFileName(kvp.Key),
            Overwrite = true
        }).ToList();

        var job = new TransferJob
        {
            Description = description,
            Type = TransferJobType.BatchDownload,
            Config = config,
            Items = items,
            Priority = TransferPriority.Normal
        };

        return QueueTransfer(job);
    }

    private async Task ProcessTransferQueue()
    {
        _logger.Info("Transfer queue processing started");

        while (!_cancellationTokenSource.Token.IsCancellationRequested)
        {
            try
            {
                if (_transferQueue.TryDequeue(out var job))
                {
                    await _concurrencyLimiter.WaitAsync(_cancellationTokenSource.Token);

                    _ = Task.Run(async () =>
                    {
                        try
                        {
                            await ProcessTransferJob(job);
                        }
                        finally
                        {
                            _concurrencyLimiter.Release();
                        }
                    }, _cancellationTokenSource.Token);
                }
                else
                {
                    // No jobs in queue, wait a bit
                    await Task.Delay(1000, _cancellationTokenSource.Token);
                }
            }
            catch (OperationCanceledException)
            {
                break;
            }
            catch (Exception ex)
            {
                _logger.Error("Error in transfer queue processing", ex);
                await Task.Delay(5000, _cancellationTokenSource.Token); // Wait before retrying
            }
        }

        _logger.Info("Transfer queue processing stopped");
    }

    private async Task ProcessTransferJob(TransferJob job)
    {
        var result = new TransferJobResult
        {
            JobId = job.Id,
            Description = job.Description,
            StartTime = DateTime.UtcNow,
            Status = TransferJobStatus.InProgress
        };

        job.Status = TransferJobStatus.InProgress;
        job.StartedAt = result.StartTime;

        _logger.Info($"Starting transfer job: {job.Id} - {job.Description}");

        var clientKey = $"{job.Config.Protocol}_{job.Config.HostName}_{job.Config.UserName}";
        var client = _activeClients.GetOrAdd(clientKey, _ => new FileTransferClient());

        try
        {
            // Connect if not already connected
            if (!client.IsConnected)
            {
                _logger.Debug($"Connecting to {job.Config.HostName} via {job.Config.Protocol}");
                client.Connect(job.Config);
            }

            // Set up progress tracking
            var progressTracker = new JobProgressTracker(job, _logger);
            client.ProgressChanged += progressTracker.OnProgressChanged;

            FileTransferResult transferResult;

            switch (job.Type)
            {
                case TransferJobType.Upload:
                    transferResult = await client.UploadAsync(
                        job.Items.First().SourcePath,
                        job.Items.First().DestinationPath
                    );
                    break;

                case TransferJobType.Download:
                    transferResult = await client.DownloadAsync(
                        job.Items.First().SourcePath,
                        job.Items.First().DestinationPath
                    );
                    break;

                case TransferJobType.BatchUpload:
                    transferResult = await client.UploadBatchAsync(job.Items);
                    break;

                case TransferJobType.BatchDownload:
                    transferResult = await client.DownloadBatchAsync(job.Items);
                    break;

                default:
                    throw new InvalidOperationException($"Unknown transfer job type: {job.Type}");
            }

            // Process result
            result.Success = transferResult.IsSuccess;
            result.ErrorMessage = transferResult.ErrorMessage;
            result.TransferredFiles = transferResult.TransferedFiles?.Count ?? 0;
            result.FailedFiles = transferResult.FailedFiles?.Count ?? 0;
            result.TotalBytes = transferResult.TransferedFiles?.Sum(f => f.FileSize) ?? 0;

            if (transferResult.IsSuccess)
            {
                job.Status = TransferJobStatus.Completed;
                result.Status = TransferJobStatus.Completed;
                _logger.Info($"Transfer job completed successfully: {job.Id}");
            }
            else
            {
                job.Status = TransferJobStatus.Failed;
                result.Status = TransferJobStatus.Failed;
                _logger.Error($"Transfer job failed: {job.Id} - {transferResult.ErrorMessage}");
            }
        }
        catch (Exception ex)
        {
            job.Status = TransferJobStatus.Failed;
            result.Success = false;
            result.Status = TransferJobStatus.Failed;
            result.ErrorMessage = ex.Message;

            _logger.Error($"Transfer job exception: {job.Id}", ex);

            // Remove failed client from active clients
            if (_activeClients.TryRemove(clientKey, out var failedClient))
            {
                try
                {
                    failedClient.Disconnect();
                    failedClient.Dispose();
                }
                catch { /* Ignore cleanup errors */ }
            }
        }
        finally
        {
            result.EndTime = DateTime.UtcNow;
            result.Duration = result.EndTime - result.StartTime;
            job.CompletedAt = result.EndTime;

            // Store result in history
            lock (_transferHistory)
            {
                _transferHistory.Add(result);

                // Keep only last 1000 results
                if (_transferHistory.Count > 1000)
                {
                    _transferHistory.RemoveRange(0, 100);
                }
            }

            // Notify completion
            OnJobCompleted?.Invoke(job, result);
        }
    }

    public TransferServiceStatistics GetStatistics()
    {
        lock (_transferHistory)
        {
            var now = DateTime.UtcNow;
            var last24Hours = _transferHistory.Where(r => r.StartTime > now.AddHours(-24)).ToList();
            var successful = last24Hours.Where(r => r.Success).ToList();
            var failed = last24Hours.Where(r => !r.Success).ToList();

            return new TransferServiceStatistics
            {
                QueueLength = _transferQueue.Count,
                ActiveTransfers = _config.MaxConcurrentTransfers - _concurrencyLimiter.CurrentCount,
                ActiveClients = _activeClients.Count,
                TotalJobsLast24Hours = last24Hours.Count,
                SuccessfulJobsLast24Hours = successful.Count,
                FailedJobsLast24Hours = failed.Count,
                SuccessRate = last24Hours.Any() ? (double)successful.Count / last24Hours.Count : 0,
                TotalBytesTransferred = successful.Sum(r => r.TotalBytes),
                AverageJobDuration = successful.Any() ? successful.Average(r => r.Duration.TotalSeconds) : 0,
                LastJobTime = _transferHistory.LastOrDefault()?.StartTime
            };
        }
    }

    public List<TransferJobResult> GetRecentJobs(int count = 50)
    {
        lock (_transferHistory)
        {
            return _transferHistory
                .OrderByDescending(r => r.StartTime)
                .Take(count)
                .ToList();
        }
    }

    public void Dispose()
    {
        _logger.Info("Shutting down Enterprise File Transfer Service");

        _cancellationTokenSource.Cancel();

        try
        {
            _processingTask.Wait(TimeSpan.FromSeconds(10));
        }
        catch (Exception ex)
        {
            _logger.Warning($"Error waiting for processing task to complete: {ex.Message}");
        }

        // Disconnect all active clients
        foreach (var client in _activeClients.Values)
        {
            try
            {
                if (client.IsConnected)
                {
                    client.Disconnect();
                }
                client.Dispose();
            }
            catch (Exception ex)
            {
                _logger.Warning($"Error disconnecting client: {ex.Message}");
            }
        }

        _activeClients.Clear();
        _concurrencyLimiter.Dispose();
        _cancellationTokenSource.Dispose();

        _logger.Info("Enterprise File Transfer Service shutdown complete");
    }

    public event Action<TransferJob, TransferJobResult> OnJobCompleted;
}

