public class ProductImport
{
    [CSVColumn("Product ID", isRequired: true)]
    public int ProductId { get; set; }

    [CSVColumn("Product Name", maxLength: 100, isRequired: true)]
    public string Name { get; set; }

    [CSVColumn("Category")]
    public string Category { get; set; }

    [CSVColumn("Unit Price", format: "C")]
    public decimal Price { get; set; }

    [CSVColumn("Units in Stock")]
    public int Stock { get; set; }

    [CSVColumn("Discontinued", format: "Yes/No")]
    public bool IsDiscontinued { get; set; }

    [CSVColumn("Last Updated", format: "yyyy-MM-dd")]
    public DateTime LastUpdated { get; set; }

    // Property without attribute - will use property name
    public string Supplier { get; set; }
}

// Read CSV with automatic mapping
var csvReader = new CSVReader();
csvReader.ReadFile("products.csv");

var products = new List<ProductImport>();

foreach (var record in csvReader.Records)
{
    var product = new ProductImport
    {
        ProductId = int.Parse(record["Product ID"]),
        Name = record["Product Name"],
        Category = record["Category"],
        Price = decimal.Parse(record["Unit Price"].Replace("$", "")),
        Stock = int.Parse(record["Units in Stock"]),
        IsDiscontinued = record["Discontinued"].ToLower() == "yes",
        LastUpdated = DateTime.Parse(record["Last Updated"]),
        Supplier = record["Supplier"]
    };

    products.Add(product);
}

Console.WriteLine($"Imported {products.Count} products from CSV");

// Validate imported data
var validProducts = products.Where(p => 
    !string.IsNullOrEmpty(p.Name) && 
    p.Price > 0 &&
    p.Stock >= 0
).ToList();

Console.WriteLine($"{validProducts.Count} products passed validation");

using ByteForge.Toolkit;
