    {
        Console.WriteLine("Subdirectories:");
        foreach (var subDir in remoteDir.SubDirectories)
        {
            Console.WriteLine($"  📁 {subDir.DirectoryName}/ ({subDir.LastModified:yyyy-MM-dd})");
        }
        Console.WriteLine();
    }

    // Display files
    if (remoteDir.Files.Any())
    {
        Console.WriteLine("Files:");
        foreach (var file in remoteDir.Files.OrderByDescending(f => f.LastModified))
        {
            string sizeDisplay = FormatFileSize(file.FileSize);
            string typeIcon = GetFileTypeIcon(file.FileName);

            Console.WriteLine($"  {typeIcon} {file.FileName}");
            Console.WriteLine($"    Size: {sizeDisplay}");
            Console.WriteLine($"    Modified: {file.LastModified:yyyy-MM-dd HH:mm:ss}");
            Console.WriteLine($"    Permissions: {file.Permissions}");

            if (file.IsSymLink)
            {
                Console.WriteLine($"    → Symbolic link");
            }
            Console.WriteLine();
        }
    }

    // Download files modified in the last 7 days
    var recentFiles = remoteDir.Files
        .Where(f => f.LastModified > DateTime.Now.AddDays(-7))
        .ToList();

    if (recentFiles.Any())
    {
        Console.WriteLine($"Found {recentFiles.Count} files modified in the last 7 days");

        var downloadItems = recentFiles.Select(f => new FileTransferItem
        {
            SourcePath = f.FullPath,
            DestinationPath = @"C:\Downloads\Recent\",
            FileName = f.FileName,
            FileSize = f.FileSize,
            LastModified = f.LastModified,
            Overwrite = false
        }).ToList();

        // Create local directory if it doesn't exist
        Directory.CreateDirectory(@"C:\Downloads\Recent");

        var downloadResult = await client.DownloadBatchAsync(downloadItems);

        Console.WriteLine($"Downloaded {downloadResult.TransferedFiles.Count} recent files");
    }

    // Check for large files (> 100 MB)
    var largeFiles = remoteDir.Files
        .Where(f => f.FileSize > 100 * 1024 * 1024)
        .OrderByDescending(f => f.FileSize)
        .ToList();

    if (largeFiles.Any())
    {
        Console.WriteLine("Large files detected (> 100 MB):");
        foreach (var file in largeFiles)
        {
            Console.WriteLine($"  ⚠ {file.FileName}: {FormatFileSize(file.FileSize)}");
        }
    }

    // Recursive directory listing
    await ListDirectoryRecursive(client, "/data/", maxDepth: 3);
}
finally
{
    client.Disconnect();
}

async Task ListDirectoryRecursive(FileTransferClient client, string path, int maxDepth, int currentDepth = 0)
{
    if (currentDepth >= maxDepth) return;

    try
    {
        var dir = await client.ListDirectoryAsync(path);
        string indent = new string(' ', currentDepth * 2);

        Console.WriteLine($"{indent}📁 {dir.DirectoryName}/");

        // List files in current directory
        foreach (var file in dir.Files.Take(5)) // Limit to first 5 files
        {
            Console.WriteLine($"{indent}  📄 {file.FileName} ({FormatFileSize(file.FileSize)})");
        }

        if (dir.Files.Count > 5)
        {
            Console.WriteLine($"{indent}  ... and {dir.Files.Count - 5} more files");
        }

        // Recurse into subdirectories
        foreach (var subDir in dir.SubDirectories.Take(3)) // Limit recursion
        {
            await ListDirectoryRecursive(client, subDir.FullPath, maxDepth, currentDepth + 1);
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"{new string(' ', currentDepth * 2)}❌ Error listing {path}: {ex.Message}");
    }
}

string FormatFileSize(long bytes)
{
    string[] suffixes = { "B", "KB", "MB", "GB", "TB" };
    int counter = 0;
    decimal number = bytes;

    while (Math.Round(number / 1024) >= 1)
    {
        number /= 1024;
        counter++;
    }

    return $"{number:N1} {suffixes[counter]}";
}

string GetFileTypeIcon(string fileName)
{
    string extension = Path.GetExtension(fileName).ToLower();

    return extension switch
    {
        ".pdf" => "📄",
        ".doc" or ".docx" => "📝",
        ".xls" or ".xlsx" => "📊",
        ".txt" => "📋",
        ".csv" => "📈",
        ".zip" or ".rar" or ".7z" => "📦",
        ".jpg" or ".png" or ".gif" => "🖼️",
        ".mp4" or ".avi" or ".mov" => "🎥",
        ".mp3" or ".wav" or ".flac" => "🎵",
        ".exe" or ".msi" => "⚙️",
        ".sql" => "🗃️",
        _ => "📄"
    };
}

using ByteForge.Toolkit;
using Newtonsoft.Json;
using System;
using System.Collections.Concurrent;
using System.Collections.Generic;
using System.Linq;
using System.Threading.Tasks;

// Enterprise delta serialization service with caching and compression
public class EnterpriseDeltaService
{
    private readonly ConcurrentDictionary<string, ObjectSnapshot> _snapshotCache;
    private readonly JsonDeltaSerializer _deltaSerializer;
    private readonly ILogger _logger;
    private readonly DeltaConfiguration _config;

    public EnterpriseDeltaService(ILogger logger, DeltaConfiguration config = null)
    {
        _logger = logger;
        _config = config ?? new DeltaConfiguration();
        _snapshotCache = new ConcurrentDictionary<string, ObjectSnapshot>();
        _deltaSerializer = new JsonDeltaSerializer();

        // Start cleanup task
        _ = Task.Run(CleanupExpiredSnapshots);
    }

    public DeltaResult<T> CreateDelta<T>(T current, string snapshotKey) where T : class
    {
        var result = new DeltaResult<T>();

        try
        {
            // Get or create snapshot
            var snapshot = GetOrCreateSnapshot(current, snapshotKey);
            var original = JsonConvert.DeserializeObject<T>(snapshot.Data);

            // Generate delta
            var stopwatch = System.Diagnostics.Stopwatch.StartNew();
            string deltaJson = _deltaSerializer.SerializeDelta(current, original);
            stopwatch.Stop();

            // Calculate metrics
            string fullJson = JsonConvert.SerializeObject(current);
            var changedProperties = _deltaSerializer.GetChangedProperties(current, original);

            result.Success = true;
            result.DeltaJson = deltaJson;
            result.FullJson = fullJson;
            result.ChangedProperties = changedProperties.ToList();
            result.DeltaSize = deltaJson.Length;
            result.FullSize = fullJson.Length;
            result.CompressionRatio = (double)deltaJson.Length / fullJson.Length;
            result.SerializationTimeMs = stopwatch.ElapsedMilliseconds;
            result.BandwidthSavings = fullJson.Length - deltaJson.Length;

            // Update snapshot
            snapshot.Data = fullJson;
            snapshot.LastUsed = DateTime.UtcNow;
            snapshot.AccessCount++;

            _logger.Info($"Delta created for {snapshotKey}: {result.CompressionRatio:P1} compression, {result.BandwidthSavings} bytes saved");

        }
        catch (Exception ex)
        {
            result.Success = false;
            result.ErrorMessage = ex.Message;
            _logger.Error($"Failed to create delta for {snapshotKey}", ex);
        }

        return result;
    }

    public DeltaResult<T> ApplyDelta<T>(string deltaJson, string snapshotKey) where T : class
    {
        var result = new DeltaResult<T>();

        try
        {
            // Get snapshot
            if (!_snapshotCache.TryGetValue(snapshotKey, out var snapshot))
            {
                throw new InvalidOperationException($"No snapshot found for key: {snapshotKey}");
            }

            var original = JsonConvert.DeserializeObject<T>(snapshot.Data);

            // Apply delta
            var stopwatch = System.Diagnostics.Stopwatch.StartNew();
            var updated = _deltaSerializer.DeserializeDelta(original, deltaJson);
            stopwatch.Stop();

            result.Success = true;
            result.Current = updated;
            result.DeltaJson = deltaJson;
            result.DeserializationTimeMs = stopwatch.ElapsedMilliseconds;

            // Update snapshot
            snapshot.Data = JsonConvert.SerializeObject(updated);
            snapshot.LastUsed = DateTime.UtcNow;
            snapshot.AccessCount++;

            _logger.Info($"Delta applied for {snapshotKey} in {stopwatch.ElapsedMilliseconds}ms");
        }
        catch (Exception ex)
        {
            result.Success = false;
            result.ErrorMessage = ex.Message;
            _logger.Error($"Failed to apply delta for {snapshotKey}", ex);
        }

        return result;
    }

    public BatchDeltaResult<T> CreateBatchDeltas<T>(Dictionary<string, T> objects) where T : class
    {
        var batchResult = new BatchDeltaResult<T>
        {
            StartTime = DateTime.UtcNow
        };

        var tasks = objects.Select(async kvp =>
        {
            var result = CreateDelta(kvp.Value, kvp.Key);
            return new KeyValuePair<string, DeltaResult<T>>(kvp.Key, result);
        });

        var results = await Task.WhenAll(tasks);

        batchResult.Results = results.ToDictionary(r => r.Key, r => r.Value);
        batchResult.EndTime = DateTime.UtcNow;
        batchResult.ProcessingTimeMs = (batchResult.EndTime - batchResult.StartTime).TotalMilliseconds;
        batchResult.TotalObjects = objects.Count;
        batchResult.SuccessfulDeltas = results.Count(r => r.Value.Success);
        batchResult.TotalBandwidthSavings = results.Where(r => r.Value.Success).Sum(r => r.Value.BandwidthSavings);
        batchResult.AverageCompressionRatio = results.Where(r => r.Value.Success).Average(r => r.Value.CompressionRatio);

        _logger.Info($"Batch delta creation completed: {batchResult.SuccessfulDeltas}/{batchResult.TotalObjects} successful, {batchResult.TotalBandwidthSavings:N0} bytes saved");

        return batchResult;
    }

    private ObjectSnapshot GetOrCreateSnapshot<T>(T obj, string key)
    {
        return _snapshotCache.GetOrAdd(key, _ => new ObjectSnapshot
        {
            Key = key,
            Data = JsonConvert.SerializeObject(obj),
            Created = DateTime.UtcNow,
            LastUsed = DateTime.UtcNow,
            AccessCount = 0
        });
    }

    private async Task CleanupExpiredSnapshots()
    {
        while (true)
        {
            try
            {
                var cutoff = DateTime.UtcNow - _config.SnapshotExpiration;
                var expiredKeys = _snapshotCache
                    .Where(kvp => kvp.Value.LastUsed < cutoff)
                    .Select(kvp => kvp.Key)
                    .ToList();

                foreach (var key in expiredKeys)
                {
                    if (_snapshotCache.TryRemove(key, out var snapshot))
                    {
                        _logger.Debug($"Expired snapshot removed: {key} (last used: {snapshot.LastUsed})");
                    }
                }

                if (expiredKeys.Any())
                {
                    _logger.Info($"Cleanup completed: {expiredKeys.Count} expired snapshots removed");
                }
            }
            catch (Exception ex)
            {
                _logger.Error("Error during snapshot cleanup", ex);
            }

            await Task.Delay(_config.CleanupInterval);
        }
    }

    public DeltaServiceStatistics GetStatistics()
    {
        var snapshots = _snapshotCache.Values.ToList();

        return new DeltaServiceStatistics
        {
            TotalSnapshots = snapshots.Count,
            TotalCacheSize = snapshots.Sum(s => s.Data.Length),
            AverageSnapshotSize = snapshots.Any() ? snapshots.Average(s => s.Data.Length) : 0,
            OldestSnapshot = snapshots.Any() ? snapshots.Min(s => s.Created) : DateTime.MinValue,
            MostRecentSnapshot = snapshots.Any() ? snapshots.Max(s => s.LastUsed) : DateTime.MinValue,
            TotalAccessCount = snapshots.Sum(s => s.AccessCount),
            MostAccessedSnapshot = snapshots.OrderByDescending(s => s.AccessCount).FirstOrDefault()?.Key
        };
    }
}

// Configuration class
public class DeltaConfiguration
{
    public TimeSpan SnapshotExpiration { get; set; } = TimeSpan.FromHours(24);
    public TimeSpan CleanupInterval { get; set; } = TimeSpan.FromMinutes(15);
    public int MaxSnapshotSize { get; set; } = 1024 * 1024; // 1 MB
    public int MaxSnapshots { get; set; } = 10000;
}

// Result classes
public class DeltaResult<T> where T : class
{
    public bool Success { get; set; }
    public T Current { get; set; }
    public string DeltaJson { get; set; }
    public string FullJson { get; set; }
    public List<string> ChangedProperties { get; set; } = new();
    public int DeltaSize { get; set; }
    public int FullSize { get; set; }
    public double CompressionRatio { get; set; }
    public long SerializationTimeMs { get; set; }
    public long DeserializationTimeMs { get; set; }
    public int BandwidthSavings { get; set; }
    public string ErrorMessage { get; set; }
}

public class BatchDeltaResult<T> where T : class
{
    public Dictionary<string, DeltaResult<T>> Results { get; set; } = new();
    public DateTime StartTime { get; set; }
    public DateTime EndTime { get; set; }
    public double ProcessingTimeMs { get; set; }
    public int TotalObjects { get; set; }
    public int SuccessfulDeltas { get; set; }
    public int TotalBandwidthSavings { get; set; }
    public double AverageCompressionRatio { get; set; }
}

public class ObjectSnapshot
{
    public string Key { get; set; }
    public string Data { get; set; }
    public DateTime Created { get; set; }
    public DateTime LastUsed { get; set; }
    public int AccessCount { get; set; }
}

public class DeltaServiceStatistics
{
    public int TotalSnapshots { get; set; }
    public long TotalCacheSize { get; set; }
    public double AverageSnapshotSize { get; set; }
    public DateTime OldestSnapshot { get; set; }
    public DateTime MostRecentSnapshot { get; set; }
    public long TotalAccessCount { get; set; }
    public string MostAccessedSnapshot { get; set; }
}

