// Demonstration application
public class DeltaServiceDemo
{
    private readonly EnterpriseDeltaService _deltaService;
    private readonly ILogger _logger;

    public DeltaServiceDemo(ILogger logger)
    {
        _logger = logger;

        var config = new DeltaConfiguration
        {
            SnapshotExpiration = TimeSpan.FromMinutes(30),
            CleanupInterval = TimeSpan.FromMinutes(5)
        };

        _deltaService = new EnterpriseDeltaService(logger, config);
    }

    public async Task RunDemo()
    {
        Console.WriteLine("=== Enterprise Delta Serialization Demo ===\n");

        // Create sample products
        var products = CreateSampleProducts();

        // Demonstrate single product delta
        await DemonstrateSingleProductDelta(products.First());

        // Demonstrate batch processing
        await DemonstrateBatchProcessing(products);

        // Show statistics
        ShowStatistics();
    }

    private List<Product> CreateSampleProducts()
    {
        return new List<Product>
        {
            new Product
            {
                Id = 1,
                Name = "Wireless Headphones",
                Description = "High-quality wireless headphones with noise cancellation",
                Price = 299.99m,
                Stock = 50,
                Category = "Electronics",
                Manufacturer = "AudioTech",
                CreatedDate = DateTime.Now.AddDays(-30),
                LastModified = DateTime.Now.AddDays(-1),
                IsActive = true,
                Tags = new List<string> { "wireless", "bluetooth", "noise-cancelling" },
                Metadata = new ProductMetadata
                {
                    SKU = "AT-WH-001",
                    Barcode = "123456789012",
                    Weight = 0.3m,
                    Dimensions = "20x18x8 cm",
                    Color = "Black",
                    Size = "Standard"
                }
            },
            new Product
            {
                Id = 2,
                Name = "Gaming Mouse",
                Description = "Precision gaming mouse with RGB lighting",
                Price = 79.99m,
                Stock = 125,
                Category = "Electronics",
                Manufacturer = "GamePro",
                CreatedDate = DateTime.Now.AddDays(-20),
                LastModified = DateTime.Now.AddDays(-2),
                IsActive = true,
                Tags = new List<string> { "gaming", "rgb", "precision" },
                Metadata = new ProductMetadata
                {
                    SKU = "GP-GM-002",
                    Barcode = "123456789013",
                    Weight = 0.15m,
                    Dimensions = "12x7x4 cm",
                    Color = "RGB",
                    Size = "Standard"
                }
            }
        };
    }

    private async Task DemonstrateSingleProductDelta(Product product)
    {
        Console.WriteLine("1. Single Product Delta Demonstration");
        Console.WriteLine("====================================");

        // Create initial snapshot
        string productKey = $"product_{product.Id}";
        var result1 = _deltaService.CreateDelta(product, productKey);

        Console.WriteLine($"Initial snapshot created for {product.Name}");
        Console.WriteLine($"Full size: {result1.FullSize:N0} bytes");
        Console.WriteLine();

        // Modify product
        product.Price = 279.99m;  // Price change
        product.Stock = 45;       // Stock change
        product.Tags.Add("sale"); // Tags change
        product.LastModified = DateTime.Now;

        // Create delta
        var result2 = _deltaService.CreateDelta(product, productKey);

        Console.WriteLine("After modifications:");
        Console.WriteLine($"Delta JSON: {result2.DeltaJson}");
        Console.WriteLine($"Changed properties: {string.Join(", ", result2.ChangedProperties)}");
        Console.WriteLine($"Delta size: {result2.DeltaSize:N0} bytes");
        Console.WriteLine($"Compression ratio: {result2.CompressionRatio:P1}");
        Console.WriteLine($"Bandwidth savings: {result2.BandwidthSavings:N0} bytes");
        Console.WriteLine($"Serialization time: {result2.SerializationTimeMs}ms");
        Console.WriteLine();
    }

    private async Task DemonstrateBatchProcessing(List<Product> products)
    {
        Console.WriteLine("2. Batch Processing Demonstration");
        Console.WriteLine("=================================");

        // Create product dictionary
        var productDict = products.ToDictionary(p => $"product_{p.Id}", p => p);

        // First batch - initial snapshots
        var batchResult1 = await _deltaService.CreateBatchDeltas(productDict);

        Console.WriteLine("Initial batch processing:");
        Console.WriteLine($"Processed: {batchResult1.TotalObjects} products");
        Console.WriteLine($"Successful: {batchResult1.SuccessfulDeltas}");
        Console.WriteLine($"Processing time: {batchResult1.ProcessingTimeMs:F0}ms");
        Console.WriteLine();

        // Modify all products
        foreach (var product in products)
        {
            product.Price *= 0.9m;  // 10% discount
            product.LastModified = DateTime.Now;
        }

        // Second batch - deltas
        var batchResult2 = await _deltaService.CreateBatchDeltas(productDict);

        Console.WriteLine("After modifications (deltas):");
        Console.WriteLine($"Total bandwidth savings: {batchResult2.TotalBandwidthSavings:N0} bytes");
        Console.WriteLine($"Average compression: {batchResult2.AverageCompressionRatio:P1}");
        Console.WriteLine($"Processing time: {batchResult2.ProcessingTimeMs:F0}ms");
        Console.WriteLine();

        // Show individual results
        foreach (var result in batchResult2.Results.Where(r => r.Value.Success))
        {
            Console.WriteLine($"  {result.Key}: {result.Value.CompressionRatio:P1} compression, " +
                            $"{result.Value.BandwidthSavings:N0} bytes saved");
        }
        Console.WriteLine();
    }

    private void ShowStatistics()
    {
        Console.WriteLine("3. Service Statistics");
        Console.WriteLine("====================");

        var stats = _deltaService.GetStatistics();

        Console.WriteLine($"Total snapshots: {stats.TotalSnapshots:N0}");
        Console.WriteLine($"Total cache size: {stats.TotalCacheSize:N0} bytes");
        Console.WriteLine($"Average snapshot size: {stats.AverageSnapshotSize:F0} bytes");
        Console.WriteLine($"Oldest snapshot: {stats.OldestSnapshot:yyyy-MM-dd HH:mm:ss}");
        Console.WriteLine($"Most recent: {stats.MostRecentSnapshot:yyyy-MM-dd HH:mm:ss}");
        Console.WriteLine($"Total accesses: {stats.TotalAccessCount:N0}");
        Console.WriteLine($"Most accessed: {stats.MostAccessedSnapshot}");
    }
}

