{
    [Required]
    public string SmtpServer { get; set; }

    public int SmtpPort { get; set; } = 587;
    public bool EnableSSL { get; set; } = true;

    [Required]
    public string Username { get; set; }

    [Required]  
    public string Password { get; set; }

