void ProcessAttachmentContent(byte[] content, string fileName)
{
    string extension = Path.GetExtension(fileName).ToLower();

    switch (extension)
    {
        case ".txt":
            string text = Encoding.UTF8.GetString(content);
            Console.WriteLine($"Text content: {text.Substring(0, Math.Min(100, text.Length))}...");
            break;

        case ".pdf":
            Console.WriteLine($"PDF document: {content.Length:N0} bytes");
            // Process PDF content
            break;

        case ".xlsx":
            Console.WriteLine($"Excel document: {content.Length:N0} bytes");
            // Process Excel content
            break;

        default:
            Console.WriteLine($"Binary content: {content.Length:N0} bytes");
            break;
    }
}

// Create handler with custom settings
var handler = new EmailAttachmentHandler();

// Define acceptable file types
var acceptedExtensions = new HashSet<string>(StringComparer.OrdinalIgnoreCase)
{
    ".pdf", ".docx", ".xlsx", ".txt", ".csv", ".jpg", ".png"
};

// Define size limits (50 MB)
const long MAX_FILE_SIZE = 50 * 1024 * 1024;

var processedAttachments = new List<AttachmentProcessResult>();
var skippedFiles = new List<SkippedFile>();

foreach (var attachment in email.Attachments)
{
    // Check file extension
    string extension = Path.GetExtension(attachment.Name ?? "").ToLower();
    if (!acceptedExtensions.Contains(extension))
    {
        skippedFiles.Add(new SkippedFile
        {
            FileName = attachment.Name,
            Reason = $"Unsupported file type: {extension}",
            SkippedAt = DateTime.Now
        });
        continue;
    }

    // Check file size
    if (attachment.ContentStream.Length > MAX_FILE_SIZE)
    {
        skippedFiles.Add(new SkippedFile
        {
            FileName = attachment.Name,
            Reason = $"File too large: {attachment.ContentStream.Length:N0} bytes",
            SkippedAt = DateTime.Now
        });
        continue;
    }

    // Check for dangerous file names
    if (IsDangerousFileName(attachment.Name))
    {
        skippedFiles.Add(new SkippedFile
        {
            FileName = attachment.Name,
            Reason = "Potentially dangerous file name",
            SkippedAt = DateTime.Now
        });
        continue;
    }

    // Process accepted attachment
    try
    {
        var result = handler.ProcessAttachment(attachment);
        processedAttachments.Add(result);

        if (result.IsSuccess)
        {
            Console.WriteLine($"✓ Processed: {result.OriginalFileName} ({result.TempFile.FileSize:N0} bytes)");
        }
        else
        {
            Console.WriteLine($"⚠ Processing error: {result.OriginalFileName} - {result.ErrorMessage}");
        }
    }
    catch (Exception ex)
    {
        Console.WriteLine($"✗ Exception processing {attachment.Name}: {ex.Message}");
        skippedFiles.Add(new SkippedFile
        {
            FileName = attachment.Name,
            Reason = $"Processing exception: {ex.Message}",
            SkippedAt = DateTime.Now
        });
    }
}

// Report processing results
Console.WriteLine($"\nProcessing Summary:");
Console.WriteLine($"  Processed: {processedAttachments.Count(r => r.IsSuccess)} files");
Console.WriteLine($"  Failed: {processedAttachments.Count(r => !r.IsSuccess)} files");
Console.WriteLine($"  Skipped: {skippedFiles.Count} files");

// Show skipped files
if (skippedFiles.Any())
{
    Console.WriteLine($"\nSkipped files:");
    foreach (var skipped in skippedFiles)
    {
        Console.WriteLine($"  - {skipped.FileName}: {skipped.Reason}");
    }
}

bool IsDangerousFileName(string fileName)
{
    if (string.IsNullOrEmpty(fileName))
        return false;

    var dangerousExtensions = new[] { ".exe", ".bat", ".cmd", ".scr", ".vbs", ".js" };
    string extension = Path.GetExtension(fileName).ToLower();

    return dangerousExtensions.Contains(extension) ||
           fileName.Contains("..") ||  // Directory traversal
           Path.GetInvalidFileNameChars().Any(fileName.Contains);
}

public class EmailBatchProcessor
{
    private readonly EmailAttachmentHandler _attachmentHandler;

    public EmailBatchProcessor()
    {
        _attachmentHandler = new EmailAttachmentHandler();
    }

    public async Task ProcessEmailBatch(IEnumerable<MailMessage> emails)
    {
        var allEmails = emails.ToList();
        Console.WriteLine($"Processing batch of {allEmails.Count} emails");

        int processedEmails = 0;
        int totalAttachments = 0;
        int successfulAttachments = 0;
        var allTempFiles = new List<TempFileAttachment>();

        try
        {
            foreach (var email in allEmails)
            {
                processedEmails++;
                Console.WriteLine($"\n[{processedEmails}/{allEmails.Count}] Processing email from: {email.From}");

                if (!email.Attachments.Any())
                {
                    Console.WriteLine("  No attachments - skipping");
                    continue;
                }

                Console.WriteLine($"  Found {email.Attachments.Count} attachments");
                totalAttachments += email.Attachments.Count;

                // Process attachments for this email
                var results = _attachmentHandler.ProcessAttachments(email.Attachments);

                foreach (var result in results)
                {
                    if (result.IsSuccess)
                    {
                        successfulAttachments++;
                        allTempFiles.Add(result.TempFile);
                        Console.WriteLine($"    ✓ {result.OriginalFileName} ({result.TempFile.FileSize:N0} bytes)");

                        // Process attachment based on type
                        await ProcessAttachmentByType(result);
                    }
                    else
                    {
                        Console.WriteLine($"    ✗ {result.OriginalFileName}: {result.ErrorMessage}");
                    }
                }

                // Show progress
                double progress = (double)processedEmails / allEmails.Count * 100;
                Console.WriteLine($"  Progress: {progress:F1}% ({processedEmails}/{allEmails.Count} emails)");
            }

            // Final summary
            Console.WriteLine($"\n=== Batch Processing Complete ===");
            Console.WriteLine($"Emails processed: {processedEmails}");
            Console.WriteLine($"Total attachments: {totalAttachments}");
            Console.WriteLine($"Successful extractions: {successfulAttachments}");
            Console.WriteLine($"Success rate: {(double)successfulAttachments / totalAttachments:P1}");

            // Generate processing report
            await GenerateProcessingReport(allTempFiles);
        }
        finally
        {
            // Always clean up temporary files
            Console.WriteLine($"\nCleaning up {allTempFiles.Count} temporary files...");
            _attachmentHandler.CleanupTemporaryFiles();
            Console.WriteLine("Cleanup complete");
        }
    }

    private async Task ProcessAttachmentByType(AttachmentProcessResult result)
    {
        string extension = Path.GetExtension(result.OriginalFileName).ToLower();

        switch (extension)
        {
            case ".csv":
                await ProcessCsvFile(result.TempFile);
                break;

            case ".xlsx":
                await ProcessExcelFile(result.TempFile);
                break;

            case ".pdf":
                await ProcessPdfFile(result.TempFile);
                break;

            case ".txt":
                await ProcessTextFile(result.TempFile);
                break;

            default:
                await ProcessGenericFile(result.TempFile);
                break;
        }
    }

    private async Task ProcessCsvFile(TempFileAttachment tempFile)
    {
        Console.WriteLine($"      Processing CSV: {tempFile.OriginalFileName}");

        try
        {
            string content = tempFile.ReadAsText();
            string[] lines = content.Split('\n');

            Console.WriteLine($"      CSV has {lines.Length} lines");

            // Process CSV data
            if (lines.Length > 1)
            {
                string header = lines[0].Trim();
                Console.WriteLine($"      Header: {header}");

                // Save to permanent location for further processing
                string permanentPath = Path.Combine(@"C:\ProcessedFiles\CSV", 
                    $"{DateTime.Now:yyyyMMdd_HHmmss}_{tempFile.OriginalFileName}");

                Directory.CreateDirectory(Path.GetDirectoryName(permanentPath));
                File.Copy(tempFile.TemporaryFilePath, permanentPath);
                Console.WriteLine($"      Saved to: {permanentPath}");
            }
        }
        catch (Exception ex)
        {
            Console.WriteLine($"      Error processing CSV: {ex.Message}");
        }
    }

    private async Task ProcessExcelFile(TempFileAttachment tempFile)
    {
        Console.WriteLine($"      Processing Excel: {tempFile.OriginalFileName}");

        // Save to dedicated Excel processing folder
        string permanentPath = Path.Combine(@"C:\ProcessedFiles\Excel", 
            $"{DateTime.Now:yyyyMMdd_HHmmss}_{tempFile.OriginalFileName}");

        Directory.CreateDirectory(Path.GetDirectoryName(permanentPath));
        File.Copy(tempFile.TemporaryFilePath, permanentPath);
        Console.WriteLine($"      Saved to: {permanentPath}");
    }

    private async Task ProcessPdfFile(TempFileAttachment tempFile)
    {
        Console.WriteLine($"      Processing PDF: {tempFile.OriginalFileName}");

        // Save to PDF archive
        string permanentPath = Path.Combine(@"C:\ProcessedFiles\PDF", 
            $"{DateTime.Now:yyyyMMdd_HHmmss}_{tempFile.OriginalFileName}");

        Directory.CreateDirectory(Path.GetDirectoryName(permanentPath));
        File.Copy(tempFile.TemporaryFilePath, permanentPath);
        Console.WriteLine($"      Saved to: {permanentPath}");
    }

    private async Task ProcessTextFile(TempFileAttachment tempFile)
    {
        Console.WriteLine($"      Processing text file: {tempFile.OriginalFileName}");

        try
        {
            string content = tempFile.ReadAsText();
            Console.WriteLine($"      Text file has {content.Length} characters");

            // Save processed text
            string permanentPath = Path.Combine(@"C:\ProcessedFiles\Text", 
                $"{DateTime.Now:yyyyMMdd_HHmmss}_{tempFile.OriginalFileName}");

            Directory.CreateDirectory(Path.GetDirectoryName(permanentPath));
            File.WriteAllText(permanentPath, content);
            Console.WriteLine($"      Saved to: {permanentPath}");
        }
        catch (Exception ex)
        {
            Console.WriteLine($"      Error processing text file: {ex.Message}");
        }
    }

    private async Task ProcessGenericFile(TempFileAttachment tempFile)
    {
        Console.WriteLine($"      Processing generic file: {tempFile.OriginalFileName}");

        // Save to general archive
        string permanentPath = Path.Combine(@"C:\ProcessedFiles\Other", 
            $"{DateTime.Now:yyyyMMdd_HHmmss}_{tempFile.OriginalFileName}");

        Directory.CreateDirectory(Path.GetDirectoryName(permanentPath));
        File.Copy(tempFile.TemporaryFilePath, permanentPath);
        Console.WriteLine($"      Saved to: {permanentPath}");
    }

    private async Task GenerateProcessingReport(List<TempFileAttachment> processedFiles)
    {
        string reportPath = Path.Combine(@"C:\ProcessedFiles\Reports", 
            $"EmailProcessingReport_{DateTime.Now:yyyyMMdd_HHmmss}.txt");

        Directory.CreateDirectory(Path.GetDirectoryName(reportPath));

        var report = new StringBuilder();
        report.AppendLine("Email Attachment Processing Report");
        report.AppendLine("==================================");
        report.AppendLine($"Generated: {DateTime.Now:yyyy-MM-dd HH:mm:ss}");
        report.AppendLine($"Total files processed: {processedFiles.Count}");
        report.AppendLine();

        // Group by file type
        var filesByType = processedFiles
            .GroupBy(f => Path.GetExtension(f.OriginalFileName).ToLower())
            .OrderByDescending(g => g.Count());

        report.AppendLine("Files by type:");
        foreach (var group in filesByType)
        {
            string extension = string.IsNullOrEmpty(group.Key) ? "(no extension)" : group.Key;
            long totalSize = group.Sum(f => f.FileSize);
            report.AppendLine($"  {extension}: {group.Count()} files, {totalSize:N0} bytes total");
        }

        report.AppendLine();
        report.AppendLine("Individual files:");
        foreach (var file in processedFiles.OrderBy(f => f.OriginalFileName))
        {
            report.AppendLine($"  {file.OriginalFileName} - {file.FileSize:N0} bytes - {file.ContentType}");
        }

        await File.WriteAllTextAsync(reportPath, report.ToString());
        Console.WriteLine($"\nProcessing report saved to: {reportPath}");
    }
}

